	(6, NULL, 3, '병원관련서식(테스트)', '원무팀', NULL, '<p>병원관련서식(테스트)<br></p>', 832, '112.161.27.82', 0, 0, 0, NULL, '2022-09-19 12:24:54', '2022-12-14 17:24:36', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, 'FID00000015', NULL, 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(7, NULL, 5, '메디인병원 온라인지원양식 다운로드 안내(테스트)', '관리자', NULL, '<p>메디인병원 온라인지원양식 다운로드 안내(테스트)<br></p>', 1116, '112.161.27.82', 0, 0, 0, NULL, '2022-09-19 12:27:27', '2022-12-05 16:09:18', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'N', NULL, '2022-09-01', '2022-09-01', NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(8, NULL, 5, 'OOO과 전담간호사 채용공고(테스트)', '관리자', NULL, '<p>[계약직] OOO과 전담간호사 채용공고(테스트)<br></p>', 920, '112.161.27.82', 0, 0, 0, NULL, '2022-09-19 12:28:13', '2022-12-05 16:09:07', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'N', NULL, '2022-09-01', '2022-09-01', NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(10, NULL, 7, '﻿[파주 메디인병원] 세계 신장암의 날, 조기 발견과 운동요법의 중요성', '관리자', NULL, '<p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><img src="/uploads/editor/371c9fe3bb9f3c8127b9a2c519a65035.png" data-filename="블로그_썸네일.png" style="width: 700px;"></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><br></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-de8d67b1-fb6f-40fe-9048-b52dc78afafe" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">국립암센터</span><span id="SE-28271acb-d9e7-4982-aa85-b08c2021f839" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">가 2021년 발표한&nbsp;</span><span id="SE-c5bf2bdc-b0ac-471f-91da-b2e8dac17456" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">2019년 암등록통계</span><span id="SE-856523e5-9d6f-4850-8f23-627ced32c988" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">에 따르면 2019년&nbsp;</span><span id="SE-b0c2edcd-7e12-47c9-87e9-1bf4bc2f00f3" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">전체 암발생자수 중 6,026명은 신장암으로 전체의 2.4%, 10위</span><span id="SE-dcb39830-cc63-4d57-bb34-090f81e3f33a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">를 차지했습니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-dcb39830-cc63-4d57-bb34-090f81e3f33a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">또한&nbsp;</span><span id="SE-4918b40d-0692-439d-a531-c55fcd229d53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">건강보험심사평가원의 국민관심질병통계</span><span id="SE-d3a5c091-21f5-43ff-8fcc-24fd2084ea3a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">에 따르면&nbsp;</span><span id="SE-81e810a3-c1dd-4887-a2e1-0d3a104b2fb0" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">2021년 전체 신장암 환자는 36,340명</span><span id="SE-9ec9af4f-4b7d-4193-bd12-8a2f9c2cb16d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">으로&nbsp;</span><span id="SE-579eae54-cd29-4777-959b-e6ee5509aac9" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">최근 5년 간 꾸준히 상승</span><span id="SE-d75979d1-c96e-48fc-9d3a-db38ade13522" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">해 주의를 요하고 있습니다.</span><br></p><p id="SE-d50e3efe-a153-4270-94fc-843f897959b1" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;="" line-height:="" 2;"="" style="font-size: 13px; letter-spacing: -0.26px;"><b><span id="SE-b7f29dac-a0bf-42fd-aff6-4750b6cb69ed" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">오늘은</span><span id="SE-dc598bba-1f38-40ed-98b6-781eb6cfc995" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">&nbsp;세계 신장암의 날을 맞아 신장암 조기 발견과 운동요법의 중요성</span><span id="SE-9fadecf1-0009-4775-b058-b3fce92dd09f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">에 대해 알아보겠습니다.</span></b></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">﻿</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><img src="/uploads/editor/5c68e35b620fd8ec20ba5308cc571b74.png" data-filename="신장암_환자_그래프.png" style="width: 676.75px;"></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><img src="/uploads/editor/fe4a67302ba28be85171c3f76fb151fa.png" data-filename="그림1.png" style="width: 338px;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><b style="color: rgb(206, 0, 0);"><span style="font-size: 24px; font-family: NanumGothic; letter-spacing: normal;">﻿l&nbsp;</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"="" style=""></span><span style="font-size: 24px; font-family: NanumGothic; letter-spacing: normal;">세계 신장암의 날</span></b></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""></span><span id="SE-1b3a55c0-0829-45f5-a469-c224706e0aac" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">매년 6월 셋째 주 목요일은 신장암 치료 방법 결정의 중요성</span><span id="SE-c9b3af71-e320-4bc9-bd3a-7d1673d43155" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">과</span><span id="SE-4b11b072-eac9-40c1-a927-c7ab703a46fc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">&nbsp;의학적 연구를 위한 임상 실험의 중요성 등</span><span id="SE-befdedb9-b277-4316-ba72-d974fca91814" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">을 알리기 위해&nbsp;</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-c404e613-cc7b-49bd-903d-6111279959d4" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">국제 신장암 연합 (IKCC)</span><span id="SE-685b19ab-3fc5-42a9-83ed-8e1492ca475f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">에서 제정한&nbsp;</span><span id="SE-163eda79-f2bf-4c93-a841-c1b96460f713" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">‘세계 신장암의 날’</span><span id="SE-b78406a6-2b8b-485c-93b5-ff2733cc7472" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">입니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-b78406a6-2b8b-485c-93b5-ff2733cc7472" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">이들은 당해 주제에 맞는&nbsp;</span><span id="SE-c5273ea7-0ab1-4d81-a225-8872d09f0679" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">영상 제작, 설문지 배포, 캠페인 전개</span><span id="SE-39e928c7-a8d4-486a-b916-580844c81825" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">&nbsp;등 다양한 활동을 진행하고 있습니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-39e928c7-a8d4-486a-b916-580844c81825" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">올해의 주제는&nbsp;</span><span id="SE-1dce31dd-52b3-45e7-83b2-882dd50e746c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">‘치료 결정권에 대해 이야기할 필요가 있습니다.’</span><span id="SE-296231f0-7cd9-4814-a5d5-c64e94fc6507" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">입니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-296231f0-7cd9-4814-a5d5-c64e94fc6507" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">국내에서도&nbsp;</span><span id="SE-6badd07a-684d-4d61-9b58-8f41ff414fee" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">한국신장암환우회</span><span id="SE-166981fa-03bd-4e7a-bd64-e60d2fa46502" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">에서 국제 신장암 연합과 함께 국제 신장암의 날 캠페인을 진행하고 있습니다.</span><span style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">﻿</span><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><img src="/uploads/editor/06c715681be87cc847d862cdd9ffcaed.jpg" data-filename="세계신장암의날_신장암환우회.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 636px;"><br></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""></span><span id="SE-5daf5606-1638-44dc-b926-1e06e341669a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">신장은 복막의 뒤쪽에 분리되어 위치하고 있기 때문에 암이 상당히 진행될 때까지 아무 증상도 느끼지 못하는 경우가 많습니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-5daf5606-1638-44dc-b926-1e06e341669a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">또한 신장암은 진행될 경우&nbsp;</span><span id="SE-d6bade30-24c6-492c-89c9-e03500fa682d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">방사선치료나 항암치료에도 잘 반응하지 않으므로&nbsp;</span><span id="SE-b28080d4-7a75-41f4-910f-19f307ba226e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">조기 진단이 매우 중요합니다.</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-b28080d4-7a75-41f4-910f-19f307ba226e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">먼저 신장암과 그 증상에 대해 알아보겠습니다.</span><span style="font-size: 16px; font-family: NanumGothic; letter-spacing: normal;">﻿</span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span><span style="font-weight: bold; color: rgb(206, 0, 0);"><span style="font-size: 24px; font-family: NanumGothic; letter-spacing: normal;">﻿l&nbsp;</span><span style="font-size: 24px; font-family: NanumGothic; letter-spacing: normal;">신장암이란?</span></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><img src="/uploads/editor/0c29fd564e2008c672b87cc275391b86.png" data-filename="human-body-anatomy-1279987_1920.png" style="width: 676.75px;"><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><p style="font-size: 13px; letter-spacing: -0.26px; line-height: 2;"><span id="SE-55479fd1-37fb-429f-a4dc-b3ecaec4e9ba" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">신장암</span><span id="SE-6ddad974-6855-47d4-8a2b-97e72d5bd786" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">은 신장의&nbsp;</span><span id="SE-131e883b-8195-455d-8794-05c5bf464b14" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">실질</span><span id="SE-5088c089-bff9-4422-93db-6b09b0898537" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">&nbsp;(소변을 만드는 세포들이 모인 부분, 수질과 피질로 구성)에서 발생하는 신장세포 암으로,</span><span malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;"=""><br></span></p><div class="se-component se-text se-l-default" id="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-compid="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-a11y-title="본문" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;="" line-height:="" 2;"="" style="font-size: 13px; letter-spacing: -0.26px;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-0cd2b8ce-26f8-49a9-ba2d-3e99413e6a19" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-42e18554-007a-4db5-ae23-4856dd43c04c" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">주로 60~70대의 노년층에서 발생하였으나 최근 영상 장비의 발달과 건강검진의 보편화로 인하여 50대 이하에서도 발견되는 일이 늘어나고 있습니다.</span><br></p><p id="SE-b2875d05-d530-4b5b-99b3-251f53b57c41" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-8471f87a-9f8d-4160-9c02-068b26737735" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-032863b2-23af-4bac-bcef-8b20bb79be17" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암의 발생 요인은&nbsp;</span><span id="SE-dfd98758-de5a-450d-aac6-c6dfd8b0c130" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환경적 요인, 기존 질병, 유전적 요인</span><span id="SE-8faa9384-7469-4f8e-993a-70c04b8a3676" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로 나눌 수 있습니다.&nbsp;</span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-11ed81cf-c4ba-4de7-b5aa-a921791f2375" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환경적 요인</span><span id="SE-04bb4dff-15a5-418e-aa59-c78b8ff7ddd6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 되는 요소는&nbsp;</span><span id="SE-c226dee5-c822-4063-8afe-9a6555d41f86" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">흡연과 고혈압</span><span id="SE-2b98a06b-a35f-4278-b308-6eb8c2a9f466" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">등이 있으며, 특히 흡연의 경우&nbsp;</span><span id="SE-fbfe915d-11fe-44d9-8c46-215f9dc4af95" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">적게는 30%, 크게는 2배까지 암의 발생률을 증가</span><span id="SE-21c0bfe6-71c2-4d82-8a63-924c93ad7b6f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">시키는 것으로 나타났습니다.&nbsp;</span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-7f0aae49-53d1-4a5b-9b48-38bc37f950a5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">기존 질병 요인</span><span id="SE-f33ad6f7-da93-4171-8700-476231247eb2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로는&nbsp;</span><span id="SE-d04b4494-bfa9-4ecb-be0d-6a36845eb732" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">장기간의 혈액 투석</span><span id="SE-3f886803-975c-4d83-bf90-302e76e864e0" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 들 수 있으며,&nbsp;</span><span id="SE-02ce7d52-d9d1-4f53-acc2-8cd864e2ad3d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">유전적 요인</span><span id="SE-7cf1272d-eab6-45d9-bb20-13c612a1b5c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로는 몇가지 염색체의 이상으로 인해 발생하는 경우가 있습니다.</span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-7cf1272d-eab6-45d9-bb20-13c612a1b5c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">그 중 가장 유명한&nbsp;</span><span id="SE-5b14470a-4508-45ec-aed1-8e9f337442d7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">유전성 신장암은 본히펠린다우증후군 (Von-Hippel-Lindau syndrome)</span><span id="SE-bf8b29a6-2f74-40ca-bb72-02221d9c7df7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">입니다.</span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><br></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-a11y-title="인용구" malgun="" gothic";="" font-size:="" medium;="" letter-spacing:="" normal;="" line-height:="" 2;"="" style="font-size: 13px; letter-spacing: -0.26px;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-c87efff0-fa7e-4c51-8891-f217432c5dfb" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-61548633-11d0-4531-850e-ce494dda545b" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-6345600e-626e-41a9-9ceb-f23bf8b85ec8" class="se-ff-nanummyeongjo se-fs24 __se-node" style="font-size: 24px; font-family: NanumGothic; font-weight: bold; color: rgb(206, 0, 0);">l 신장암의 증상과 진단</span></p></div><div id="SE-4b16ec53-f619-4c97-a4f4-9cca0f2e233f" class="se-module se-module-text __se-unit se-is-empty se-cite" style="line-height: 2;"><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><img src="/uploads/editor/2783f972795eaec801cdf4856ea1d97e.png" data-filename="silence-1715729_1920.png" style="width: 676.75px;"><span style="font-size: medium;"><br></span></p><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><br><span id="SE-a28fadfe-2b2a-448d-bb1f-2afd11427f1f" class="se-ff-nanumgothic se-fs13 __se-node" style="color: rgb(119, 119, 119);"></span></p><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-size: medium;"></span><div class="se-component se-text se-l-default" id="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-compid="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-a11y-title="본문" style="font-size: medium; line-height: 2;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-3bf1ec78-e037-4301-aab7-f9036a158bee" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-90abbb69-b6fc-4aac-9118-95e8e5b152b6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암은 종양의 크기가 작은&nbsp;</span><span id="SE-b1283b2e-e5cb-4cf2-bf2e-3d392b061776" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">초기에는 증상이 거의 없으며</span><span id="SE-6fc91d87-c79e-4f01-ba3f-73c907b3fd5a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">, 종양이 커져&nbsp;</span><span id="SE-49fb58bb-d9c2-4e4c-908b-f6334f20284f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">장기를 밀어낼 정도가 되어야만 비로소 증상</span><span id="SE-01261727-1651-47a3-a4b0-1bde0594eac2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 나타납니다.</span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-01261727-1651-47a3-a4b0-1bde0594eac2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">따라서 진단이 늦어져&nbsp;</span><span id="SE-b2a75727-1a4d-447b-9428-f3e47a9d7481" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">처음 진단되는 환자의 30% 가량은 이미 전이가 발생한 상태</span><span id="SE-104c0f2d-4c80-485a-8f48-d7c72f940d7f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로 나타나게 됩니다.</span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-104c0f2d-4c80-485a-8f48-d7c72f940d7f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">가장 흔한 증상은&nbsp;</span><span id="SE-00bff87e-4d6d-4d55-b2fe-6dac6dd328f5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">혈뇨</span><span id="SE-b93d4acf-0a70-4cfd-9c07-b6e1ca79543a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로&nbsp;</span><span id="SE-cf666aa9-f6a4-476a-b4cb-d2d1425e5a75" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환자의 60%</span><span id="SE-dc6cb145-769b-4399-a150-6e9b6b104630" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">정도에게서 나타납니다.</span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-dc6cb145-769b-4399-a150-6e9b6b104630" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이외에는&nbsp;</span><span id="SE-d3be7f18-9f86-4774-b41e-48e19dec4a8a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이된 부위에 따라 호흡곤란, 기침, 두통 등 다양한 증상</span><span id="SE-8e505b8a-1ed7-4607-8df0-dd800d0a9fef" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 나타나 이러한 증상때문에 신장암을 발견하게 되는 경우도 전체 환자의 30%에 이릅니다.</span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-8e505b8a-1ed7-4607-8df0-dd800d0a9fef" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또한 신장암은 암세포가 생산하는&nbsp;</span><span id="SE-510969f9-fa93-41fc-88eb-5b809bb73f09" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">특정 호르몬이 고혈압, 고칼슘혈증, 간기능의 이상</span><span id="SE-a016c9de-a723-4d41-b89f-c280e13e3ffc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">&nbsp;등을 일으킬 수 있기 때문에 그러한 증상을 검사하던 중 종양이 발견되는 경우도 있습니다.</span><br></p><p id="SE-6743a056-5b1f-419a-9ec0-467bfe5dc54d" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-021fab4a-c37f-411d-95e5-3b32ce51978a" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-b40c0149-fe8d-4a4f-91e7-5cf0a5972695" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암은 앞서 말씀드린 것처럼 이렇다 할 증상이 나타나지 않으며 이로 인해 다른 부위로 전이되는 경우가 많습니다.</span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-b40c0149-fe8d-4a4f-91e7-5cf0a5972695" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또&nbsp;</span><span id="SE-d138cbfa-5284-479d-8290-9e9fb2f44e2e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">초기인 1기에 발견할 경우 5년 생존율이 90%</span><span id="SE-925c9996-cd62-46c8-a71d-cc9d64efe9e8" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">에 이르지만&nbsp;</span><span id="SE-56ffc8cd-7515-4093-b879-8dd16b98f79d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">4기에 발견되면 최대 생존율 20%,</span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-56ffc8cd-7515-4093-b879-8dd16b98f79d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">평균 생존 기간이 약 2~3년</span><span id="SE-9ad9063d-9507-41f9-af9c-0ee8272609d2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">&nbsp;정도로 예후가 매우 나쁘기 때문에&nbsp;</span><span id="SE-e766c201-80f2-4fc0-9363-6134af558950" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">선제적이고 정기적인 건강 검진</span><span id="SE-6477f07c-f962-4401-ba7c-922f12f50074" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 통한 조기 발견이 중요합니다.</span><br></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-6477f07c-f962-4401-ba7c-922f12f50074" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암의 진단은 주로 건강검진을 통해 이루어지는 경우가 많습니다.</span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-a7a26291-6938-4e44-b832-ff46e60e4dfc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복부 초음파 검사</span><span id="SE-f744f7f0-c7dd-4aa0-9a98-2b7bec898c09" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">가 널리 이용되며, 초음파 검사에서 종양 물질이 발견될 경우&nbsp;</span><span id="SE-0bcf5f52-8138-41ed-9ad3-7011cc867370" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복부 전산화단층촬영 (CT)</span><span id="SE-cde02bf5-0f80-4bfa-b9cb-4fce53fa36d2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로 종양 물질에 대한 정확한 평가와 혈관,</span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">신장 주위 임파선 및 주위 장기에 대한 전이 여부를 평가할 수 있습니다.</span><br></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">또한 폐 전이 및 뼈 전이에 대한 검사도 고려해야 합니다.</span><br></p><p id="SE-c3d33ad0-86e5-4d2d-a769-689c1bb508e1" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-2d012cb3-d3a6-4c60-8edf-8ac5c688c3ed" class="se-ff-nanumgothic se-fs19 __se-node"></span></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-a11y-title="인용구" style="font-size: medium; line-height: 2;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-521325b5-fe99-47f0-9001-208fa98dea87" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="color: rgb(206, 0, 0); font-family: NanumGothic; font-size: 24px; font-weight: bold; letter-spacing: -0.26px;">l 신장암의 치료와 운동 요법</span><br></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-df82fb2c-a7e6-4d1f-991f-39b2dde578e1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암의 치료</span><span id="SE-f9296307-370c-49ca-a840-bc033382dcd5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">는 다른 기관으로&nbsp;</span><span id="SE-0ea68947-af4b-4bc2-8b2c-0257ba6d9e53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이된 경우</span><span id="SE-a9fa86f8-9e70-48c5-bbf9-077e86358b7d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">와&nbsp;</span><span id="SE-82a0e38e-c88c-45c9-ba81-c3ea334cd685" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">그렇지 않은 경우</span><span id="SE-aae2abc3-89a0-44c7-a5a0-5ef6f15b032a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로 나뉩니다.</span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-aae2abc3-89a0-44c7-a5a0-5ef6f15b032a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이되지 않았을 경우에는&nbsp;</span><span id="SE-75021b1c-c48c-4b9f-88cd-da420ab4ed40" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장과 주위 정상 조직을 광범위하게 절제</span><span id="SE-51e7e3e4-69ea-411e-bfe4-fa57c8dfba46" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">하는 수술을 통해 치료합니다.</span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-51e7e3e4-69ea-411e-bfe4-fa57c8dfba46" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">종양이 크지 않을 때는&nbsp;</span><span id="SE-d121ba06-6ba2-4859-9ece-2a21a5eec316" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복강경을 이용해 수술</span><span id="SE-4557860f-5431-4303-975a-64058a574bc9" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">하는 경우도 있으며, 최근에는&nbsp;</span><span id="SE-632c9fca-c1c3-4f49-b98b-e512f8473b8f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로봇수술</span><span id="SE-02280a90-f8c3-4236-a774-f01cb3a87d7c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">역시 각광받고 있습니다.</span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-02280a90-f8c3-4236-a774-f01cb3a87d7c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환자의 나이가&nbsp;</span><span id="SE-60967970-6cdd-4abe-b356-955ce9d0290c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">젊거나 종양 크기가 작을 때는 신장 부분 절제술</span><span id="SE-fefa0f26-6955-45bc-8d3e-bbedb19fc518" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 시행하기도 합니다.</span><br></p></div></div></div></div></div></div><div class="se-component se-text se-l-default" id="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-compid="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-a11y-title="본문" style="font-size: medium; line-height: 2;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-1b4920f2-c4e6-459b-9b87-eb8359d3f69e" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-20d5df14-7534-4da2-ae59-a552167e2f8d" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9daa0bc4-d7c4-4e9e-8fca-9100a176ac78" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9c067790-5997-4d4d-b420-82a4478a22ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암이&nbsp;</span><span id="SE-a3f6f3c3-04a0-4885-9101-016b8b428448" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">한 장기로만 전이된 경우에는 종양만 제거</span><span id="SE-39b3691e-6f56-4aa6-b4c3-b1c7a897a183" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">하는 것이 도움이 되기도 합니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-39b3691e-6f56-4aa6-b4c3-b1c7a897a183" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이외 치료 방법은&nbsp;</span><span id="SE-dfb0acf3-8512-43cb-a107-9332cde99e1f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">면역요법, 호르몬요법, 항암 화학요법, 방사선요법</span><span id="SE-f6e08743-70a5-4dc2-b6d9-bf9a18eb42ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">등이 있습니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-f6e08743-70a5-4dc2-b6d9-bf9a18eb42ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또 예방과 치료 모두에 있어&nbsp;</span><span id="SE-1fd981eb-e07e-41bc-9fc6-83c97f0bc4bd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">운동요법의 중요성</span><span id="SE-9251053c-c147-424b-83d3-e5b6ee317c53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 강조되고 있는데, 이는 2020년 세계 신장암의 날의 주제로 나타났을 정도입니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9251053c-c147-424b-83d3-e5b6ee317c53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">당시&nbsp;</span><span id="SE-cda67035-6bc0-4844-b343-90634f1535f6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">주제는 ‘건강을 위한 운동, 우리 함께 이야기해봐요.’</span><span id="SE-2ace55d9-f612-48f9-8e6d-d69c88e23315" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로, 신장암 예방 및 예후 개선에 있어 신체 활동의 중요성을 알리기 위한 캠페인이었습니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-2ace55d9-f612-48f9-8e6d-d69c88e23315" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">국제신장암연합의 자료에 따르면 신체적으로 활동적인 것만으로 신장암&nbsp;</span><span id="SE-b8f00b1e-5537-4144-a7bd-7ef4a7d9f3b7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">발생 위험을 최대 22%까지 줄일</span><span id="SE-3fa57bb1-b66a-4f20-999b-0c5fd7bc00cd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">&nbsp;수 있으며,</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-3fa57bb1-b66a-4f20-999b-0c5fd7bc00cd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이미 발병한 이유에도&nbsp;</span><span id="SE-51528ee9-75ac-4cbc-aa8c-d725d1a08b1f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">적당한 신체활동을 통해 치료 예후를 최대 15% 향상</span><span id="SE-e91dab7b-81b7-4cd4-81b5-f64aed4a7de1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">시킬 수 있습니다.</span><br></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-e91dab7b-81b7-4cd4-81b5-f64aed4a7de1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또한 미국 로스웰파크 암연구소 연구팀의 연구에 따르면 운동을 전혀 하지 않는 사람의 경우 신장암의 발병 확률이&nbsp;</span><span id="SE-77319e4c-03ca-4dbd-8303-c9e0a1974196" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">최고 77%</span><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">까지 치솟았습니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">정상 체중을 유지하더라도 신체 활동이 없을 경우 암 발병 위험이 유의미하게 높아진다는 것입니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">따라서 신장암 치료와 예방 모든 측면에서 운동요법은&nbsp;</span><span id="SE-c61e6bcb-2015-4545-a62b-26f4e3529aca" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">생활 속에서 실천이 가능한 가장 효과적인 방법</span><span id="SE-680c2c35-3fd2-4ab8-b0db-66e723cbb6ca" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이라고 볼 수 있습니다.</span><br></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-6196c708-1fbc-449d-be48-024032da1549" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-a11y-title="인용구" style="font-size: medium; line-height: 2;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-ddc7ce83-c901-4d77-8ba4-497310ad8d74" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><img src="/uploads/editor/7f201994370abc885596fbfc3502f748.png" data-filename="메디인병원_프로필_오영승_세로.png" style="width: 800px;"></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><b>[메디인병원 신장내과 오영승 진료과장]​</b></p><p id="SE-1756c69b-2e4a-4f80-960c-e0df87c1fe9b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-d584e198-1403-41fc-b43b-f7a6cbb8cca2" class="se-ff-nanumgothic se-fs19 __se-node">건양대학교 의과대학 졸업</span></p><p id="SE-1f31128e-f1b7-42f8-9001-3ee847f856af" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-6c79a41e-5a1f-4f5b-83e8-47e60b9269be" class="se-ff-nanumgothic se-fs19 __se-node">前 순천향대학교 부천병원 신장내과 임상강사</span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4ae29ba4-f296-48fb-a46a-d1083f528cf9" class="se-ff-nanumgothic se-fs19 __se-node">가톨릭중앙의료원 전공의</span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span class="se-ff-nanumgothic se-fs19 __se-node"><br></span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4ae29ba4-f296-48fb-a46a-d1083f528cf9" class="se-ff-nanumgothic se-fs19 __se-node"><br></span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-c43feac2-b1a3-48bb-8621-3abd353ce4d8" class="se-ff-nanumgothic se-fs19 __se-node">메디인병원은 신장내과 전문의인&nbsp;</span><span id="SE-a1c1c549-90e2-44a5-867a-08ac26453fee" class="se-ff-nanumgothic se-fs19 __se-node"><b>오영승 진료과장</b></span><span id="SE-f92a77bf-c516-4816-8643-1c221f9dbff4" class="se-ff-nanumgothic se-fs19 __se-node">을 주재로&nbsp;</span><span id="SE-bdc0724a-9908-41d7-8756-9d9f3f781806" class="se-ff-nanumgothic se-fs19 __se-node"><b>신장내과</b></span><span id="SE-38285bed-a6e5-44dd-9a29-e74af4ca3b1c" class="se-ff-nanumgothic se-fs19 __se-node">와&nbsp;</span><span id="SE-805d943f-9fdf-4943-96cd-402720c53d5d" class="se-ff-nanumgothic se-fs19 __se-node"><b>인공신장클리닉</b></span><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node">을 운영하고 있습니다.</span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">신장내과와 인공신장클리닉에서는 최신식 장비와 시설로 신부전을 비롯한 신장 관련 질환의 진단과 치료 등 의료서비스를 제공하고 있습니다.</span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">특히 지난 4월 신설된&nbsp;</span><span id="SE-0dd8bf7a-1ae2-476e-9c6d-dfb93797f0a6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>인공신장클리닉</b></span><span id="SE-d0b1290f-4965-4565-b2c8-a23fb224eddc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">은&nbsp;</span><span id="SE-431e4fee-d029-4048-bfe3-b0f380332849" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>만성신부전증 신장질환 환자</b></span><span id="SE-b8675c2c-18ea-4566-8e01-d860477bf9c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">를 대상으로 증상 단계에 따라&nbsp;</span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-ed4b95f3-00f5-4d4f-8a03-cdec04b69b5a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>식이요법부터 혈액 투석, 복막 투석 치료</b></span><span id="SE-e1958b46-a029-4825-b22d-4dd5d135fb47" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">와&nbsp;</span><span id="SE-910ba600-3073-40b8-b24b-357b679720d7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>관련 합병증 치료</b></span><span id="SE-d3b0cedc-14a7-47af-84df-e84354f8e519" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">를 함께 진행합니다.</span><br></p><p class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><img src="/uploads/editor/e63c0e3cfaca9081fc076f9bf18321a3.jpg" data-filename="kite-1666816_1920.jpg" style="width: 338.375px;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-size: medium;"></span><span style="font-size: medium;">지금까지 세계 신장암의 날을 맞아 신장암과 조기 발견, 운동요법의 중요성에 대해 전해드렸습니다.</span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">신장암은 초기에 별 다른 증상이 없어 발견하기 힘들어 뒤늦게 발견할 경우 생존률이 낮지만 선제적인 건강 검진을 통해 조기에 발견할 경우 생존률이 매우 높습니다.</span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">이러한 신장암의 조기 발견을 위한 건강 검진과 꾸준한 생활 속 운동요법을 통해 건강한 삶을 보내시길 바랍니다.</span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p></div></div></div></div></div></div></div></div></div></div></div></div>', 3003, '112.161.27.82', 0, 0, 0, NULL, '2022-09-19 14:53:38', '2022-10-19 10:08:14', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000016', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(12, NULL, 8, 'test', '관리자', NULL, '<p>ada</p>', 24, '192.168.0.1', 0, 0, 0, NULL, '2022-09-20 09:12:09', '2022-09-20 09:12:09', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(15, NULL, 2, '메디인병원, 4월 30일 신축 개원…파주시 최초 민간종합병원 승격  ', '관리자', NULL, NULL, 1158, '59.5.161.67', 0, 0, 0, NULL, '2022-09-27 14:05:40', '2022-09-27 14:05:40', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', '서울경제', 'https://www.sedaily.com/NewsView/265TAFZV8W/GK0101', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(18, NULL, 1, '[파주 메디인병원] [단신] 암 생존자 주간안내', '관리자', NULL, '<p>보건복지부와 국립암센터가 공개한 \'2019년 암등록통계\'에 따르면 2015년 19년까지 모든 암 생존율은 70.7%로 1993년에서 95년에 비해 27.3%p 이상 증가했습니다. 그러나 암생존자에 대한 인식은 아직 널리 퍼지지 않은 것이 현실입니다.</p><p>오늘은 암생존자 주간에 대해 안내드리겠습니다.</p>', 84, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 22:46:05', '2022-10-19 10:44:46', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(19, NULL, 1, '[파주 메디인병원] 세계 헌혈자의 날, 헌혈의 중요성', '관리자', NULL, '<p>대한적십자사의 \'2021 혈액사업통계연보\'에 따르면 2021년 국민 헌혈률은 5.04%, 전체 헌혈 건수는 260만 4,432건으로 이는 전년대비 7천 건 이상 감소한 수치이며 2015년 이래로 지속적인 하햫세를 보이고 있어 관심과 참여가 필요한 시점입니다.</p><p>오늘은 세계 헌혈자의 날을 맞아 헌혈의 중요성을 알아보겠습니다.</p>', 101, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 22:47:58', '2022-10-19 10:44:40', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(20, NULL, 1, '﻿[파주 메디인병원] 세계 신장암의 날, 조기 발견과 운동요법의 중요성', '관리자', NULL, '<p style="line-height: 2;"><img src="/uploads/editor/2377b87c9cbc7b95ff78347ac56937ca.png" style="width: 700px;" data-filename="블로그_썸네일.png"></p><p style="line-height: 2;"><br></p><p style="line-height: 2;"><span id="SE-de8d67b1-fb6f-40fe-9048-b52dc78afafe" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">국립암센터</span><span id="SE-28271acb-d9e7-4982-aa85-b08c2021f839" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">가 2021년 발표한 </span><span id="SE-c5bf2bdc-b0ac-471f-91da-b2e8dac17456" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">2019년 암등록통계</span><span id="SE-856523e5-9d6f-4850-8f23-627ced32c988" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">에 따르면 2019년 </span><span id="SE-b0c2edcd-7e12-47c9-87e9-1bf4bc2f00f3" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">전체 암발생자수 중 6,026명은 신장암으로 전체의 2.4%, 10위</span><span id="SE-dcb39830-cc63-4d57-bb34-090f81e3f33a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">를 차지했습니다. </span></p><p style="line-height: 2;"><span id="SE-dcb39830-cc63-4d57-bb34-090f81e3f33a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">또한 </span><span id="SE-4918b40d-0692-439d-a531-c55fcd229d53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">건강보험심사평가원의 국민관심질병통계</span><span id="SE-d3a5c091-21f5-43ff-8fcc-24fd2084ea3a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">에 따르면 </span><span id="SE-81e810a3-c1dd-4887-a2e1-0d3a104b2fb0" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">2021년 전체 신장암 환자는 36,340명</span><span id="SE-9ec9af4f-4b7d-4193-bd12-8a2f9c2cb16d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">으로 </span><span id="SE-579eae54-cd29-4777-959b-e6ee5509aac9" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">최근 5년 간 꾸준히 상승</span><span id="SE-d75979d1-c96e-48fc-9d3a-db38ade13522" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">해 주의를 요하고 있습니다.</span><br></p><p id="SE-d50e3efe-a153-4270-94fc-843f897959b1" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal; line-height: 2;"><b><span id="SE-b7f29dac-a0bf-42fd-aff6-4750b6cb69ed" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">오늘은</span><span id="SE-dc598bba-1f38-40ed-98b6-781eb6cfc995" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;"> 세계 신장암의 날을 맞아 신장암 조기 발견과 운동요법의 중요성</span><span id="SE-9fadecf1-0009-4775-b058-b3fce92dd09f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">에 대해 알아보겠습니다.</span></b></p><p style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">﻿</span></p><p style="line-height: 2;"><img src="/uploads/editor/17b04dda95b1ee1971af611159079e41.png" data-filename="신장암_환자_그래프.png" style="width: 50%;"></p><p style="line-height: 2;"><img src="/uploads/editor/b3b3d0e4331b7be6b9d2775c3a6a9071.png" data-filename="그림1.png" style="width: 338px;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><b style="color: rgb(156, 0, 0);"><span style="font-family: NanumGothic; font-size: 24px; letter-spacing: normal;">﻿l </span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"></span><span style="font-family: NanumGothic; font-size: 24px; letter-spacing: normal;">세계 신장암의 날</span></b></p><p style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"></span><span id="SE-1b3a55c0-0829-45f5-a469-c224706e0aac" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">매년 6월 셋째 주 목요일은 신장암 치료 방법 결정의 중요성</span><span id="SE-c9b3af71-e320-4bc9-bd3a-7d1673d43155" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">과</span><span id="SE-4b11b072-eac9-40c1-a927-c7ab703a46fc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;"> 의학적 연구를 위한 임상 실험의 중요성 등</span><span id="SE-befdedb9-b277-4316-ba72-d974fca91814" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">을 알리기 위해 </span></p><p style="line-height: 2;"><span id="SE-c404e613-cc7b-49bd-903d-6111279959d4" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">국제 신장암 연합 (IKCC)</span><span id="SE-685b19ab-3fc5-42a9-83ed-8e1492ca475f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">에서 제정한 </span><span id="SE-163eda79-f2bf-4c93-a841-c1b96460f713" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">‘세계 신장암의 날’</span><span id="SE-b78406a6-2b8b-485c-93b5-ff2733cc7472" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">입니다. </span></p><p style="line-height: 2;"><span id="SE-b78406a6-2b8b-485c-93b5-ff2733cc7472" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">이들은 당해 주제에 맞는 </span><span id="SE-c5273ea7-0ab1-4d81-a225-8872d09f0679" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">영상 제작, 설문지 배포, 캠페인 전개</span><span id="SE-39e928c7-a8d4-486a-b916-580844c81825" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;"> 등 다양한 활동을 진행하고 있습니다. </span></p><p style="line-height: 2;"><span id="SE-39e928c7-a8d4-486a-b916-580844c81825" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">올해의 주제는 </span><span id="SE-1dce31dd-52b3-45e7-83b2-882dd50e746c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">‘치료 결정권에 대해 이야기할 필요가 있습니다.’</span><span id="SE-296231f0-7cd9-4814-a5d5-c64e94fc6507" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">입니다. </span></p><p style="line-height: 2;"><span id="SE-296231f0-7cd9-4814-a5d5-c64e94fc6507" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">국내에서도 </span><span id="SE-6badd07a-684d-4d61-9b58-8f41ff414fee" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">한국신장암환우회</span><span id="SE-166981fa-03bd-4e7a-bd64-e60d2fa46502" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">에서 국제 신장암 연합과 함께 국제 신장암의 날 캠페인을 진행하고 있습니다.</span><span style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">﻿</span><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><img src="/uploads/editor/42ed96574124abbfd0e896aee2258f94.jpg" data-filename="세계신장암의날_신장암환우회.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 636px;"><br></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"></span><span id="SE-5daf5606-1638-44dc-b926-1e06e341669a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">신장은 복막의 뒤쪽에 분리되어 위치하고 있기 때문에 암이 상당히 진행될 때까지 아무 증상도 느끼지 못하는 경우가 많습니다. </span></p><p style="line-height: 2;"><span id="SE-5daf5606-1638-44dc-b926-1e06e341669a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">또한 신장암은 진행될 경우 </span><span id="SE-d6bade30-24c6-492c-89c9-e03500fa682d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">방사선치료나 항암치료에도 잘 반응하지 않으므로 </span><span id="SE-b28080d4-7a75-41f4-910f-19f307ba226e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">조기 진단이 매우 중요합니다. </span></p><p style="line-height: 2;"><span id="SE-b28080d4-7a75-41f4-910f-19f307ba226e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">먼저 신장암과 그 증상에 대해 알아보겠습니다.</span><span style="font-family: NanumGothic; font-size: 16px; letter-spacing: normal;">﻿</span></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span><span style="font-weight: bold; background-color: rgb(255, 255, 255); color: rgb(255, 231, 206);"><span style="font-family: NanumGothic; font-size: 24px; letter-spacing: normal;">﻿l </span><span style="font-family: NanumGothic; font-size: 24px; letter-spacing: normal;">신장암이란?</span></span></p><p style="line-height: 2;"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><img src="/uploads/editor/ac19cb2e68372251432862ecaffae956.png" style="width: 50%;" data-filename="human-body-anatomy-1279987_1920.png"><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><p style="line-height: 2;"><span id="SE-55479fd1-37fb-429f-a4dc-b3ecaec4e9ba" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">신장암</span><span id="SE-6ddad974-6855-47d4-8a2b-97e72d5bd786" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">은 신장의 </span><span id="SE-131e883b-8195-455d-8794-05c5bf464b14" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;">실질</span><span id="SE-5088c089-bff9-4422-93db-6b09b0898537" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; letter-spacing: normal; font-family: NanumGothic;"> (소변을 만드는 세포들이 모인 부분, 수질과 피질로 구성)에서 발생하는 신장세포 암으로,</span><span style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal;"><br></span></p><div class="se-component se-text se-l-default" id="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-compid="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-a11y-title="본문" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal; line-height: 2;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-290e94ed-3847-45d2-9e8b-906bf4efb923" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-0cd2b8ce-26f8-49a9-ba2d-3e99413e6a19" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-42e18554-007a-4db5-ae23-4856dd43c04c" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px;">주로 60~70대의 노년층에서 발생하였으나 최근 영상 장비의 발달과 건강검진의 보편화로 인하여 50대 이하에서도 발견되는 일이 늘어나고 있습니다.</span><br></p><p id="SE-b2875d05-d530-4b5b-99b3-251f53b57c41" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-8471f87a-9f8d-4160-9c02-068b26737735" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-032863b2-23af-4bac-bcef-8b20bb79be17" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">신장암의 발생 요인은 </span><span id="SE-dfd98758-de5a-450d-aac6-c6dfd8b0c130" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">환경적 요인, 기존 질병, 유전적 요인</span><span id="SE-8faa9384-7469-4f8e-993a-70c04b8a3676" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">으로 나눌 수 있습니다. </span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-11ed81cf-c4ba-4de7-b5aa-a921791f2375" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환경적 요인</span><span id="SE-04bb4dff-15a5-418e-aa59-c78b8ff7ddd6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 되는 요소는 </span><span id="SE-c226dee5-c822-4063-8afe-9a6555d41f86" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">흡연과 고혈압</span><span id="SE-2b98a06b-a35f-4278-b308-6eb8c2a9f466" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">등이 있으며, 특히 흡연의 경우 </span><span id="SE-fbfe915d-11fe-44d9-8c46-215f9dc4af95" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">적게는 30%, 크게는 2배까지 암의 발생률을 증가</span><span id="SE-21c0bfe6-71c2-4d82-8a63-924c93ad7b6f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">시키는 것으로 나타났습니다. </span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-7f0aae49-53d1-4a5b-9b48-38bc37f950a5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">기존 질병 요인</span><span id="SE-f33ad6f7-da93-4171-8700-476231247eb2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로는 </span><span id="SE-d04b4494-bfa9-4ecb-be0d-6a36845eb732" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">장기간의 혈액 투석</span><span id="SE-3f886803-975c-4d83-bf90-302e76e864e0" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 들 수 있으며, </span><span id="SE-02ce7d52-d9d1-4f53-acc2-8cd864e2ad3d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">유전적 요인</span><span id="SE-7cf1272d-eab6-45d9-bb20-13c612a1b5c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로는 몇가지 염색체의 이상으로 인해 발생하는 경우가 있습니다. </span></p><p id="SE-1e4ba11a-bf86-43a8-9cb2-2163af51f995" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-7cf1272d-eab6-45d9-bb20-13c612a1b5c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">그 중 가장 유명한 </span><span id="SE-5b14470a-4508-45ec-aed1-8e9f337442d7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">유전성 신장암은 본히펠린다우증후군 (Von-Hippel-Lindau syndrome)</span><span id="SE-bf8b29a6-2f74-40ca-bb72-02221d9c7df7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">입니다.</span><br></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-a11y-title="인용구" style="font-family: "Malgun Gothic"; font-size: medium; letter-spacing: normal; line-height: 2;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-d725ee2f-a0a8-4378-9e54-af71378be5e7" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-c87efff0-fa7e-4c51-8891-f217432c5dfb" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-61548633-11d0-4531-850e-ce494dda545b" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-6345600e-626e-41a9-9ceb-f23bf8b85ec8" class="se-ff-nanummyeongjo se-fs24 __se-node" style="font-family: NanumGothic; font-size: 24px; font-weight: bold;">l 신장암의 증상과 진단</span></p></div><div id="SE-4b16ec53-f619-4c97-a4f4-9cca0f2e233f" class="se-module se-module-text __se-unit se-is-empty se-cite" style="line-height: 2;"><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><img src="/uploads/editor/fc3a1c7eae7fca16eb9c0a2f8822f8dc.png" style="width: 50%;" data-filename="silence-1715729_1920.png"><span style="font-size: medium;"><br></span></p><p id="SE-f3b77314-03fe-4f1e-86e9-194c3cd377db" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><br><span id="SE-a28fadfe-2b2a-448d-bb1f-2afd11427f1f" class="se-ff-nanumgothic se-fs13 __se-node" style="color: rgb(119, 119, 119);"></span></p><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-size: medium;"></span><div class="se-component se-text se-l-default" id="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-compid="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-a11y-title="본문" style="font-size: medium; line-height: 2;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-ac1970a0-f8b9-4154-83b2-50566f4cfd67" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-3bf1ec78-e037-4301-aab7-f9036a158bee" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-90abbb69-b6fc-4aac-9118-95e8e5b152b6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">신장암은 종양의 크기가 작은 </span><span id="SE-b1283b2e-e5cb-4cf2-bf2e-3d392b061776" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">초기에는 증상이 거의 없으며</span><span id="SE-6fc91d87-c79e-4f01-ba3f-73c907b3fd5a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">, 종양이 커져 </span><span id="SE-49fb58bb-d9c2-4e4c-908b-f6334f20284f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">장기를 밀어낼 정도가 되어야만 비로소 증상</span><span id="SE-01261727-1651-47a3-a4b0-1bde0594eac2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">이 나타납니다. </span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-01261727-1651-47a3-a4b0-1bde0594eac2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">따라서 진단이 늦어져 </span><span id="SE-b2a75727-1a4d-447b-9428-f3e47a9d7481" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">처음 진단되는 환자의 30% 가량은 이미 전이가 발생한 상태</span><span id="SE-104c0f2d-4c80-485a-8f48-d7c72f940d7f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로 나타나게 됩니다. </span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-104c0f2d-4c80-485a-8f48-d7c72f940d7f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">가장 흔한 증상은 </span><span id="SE-00bff87e-4d6d-4d55-b2fe-6dac6dd328f5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">혈뇨</span><span id="SE-b93d4acf-0a70-4cfd-9c07-b6e1ca79543a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로 </span><span id="SE-cf666aa9-f6a4-476a-b4cb-d2d1425e5a75" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환자의 60%</span><span id="SE-dc6cb145-769b-4399-a150-6e9b6b104630" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">정도에게서 나타납니다. </span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-dc6cb145-769b-4399-a150-6e9b6b104630" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이외에는 </span><span id="SE-d3be7f18-9f86-4774-b41e-48e19dec4a8a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이된 부위에 따라 호흡곤란, 기침, 두통 등 다양한 증상</span><span id="SE-8e505b8a-1ed7-4607-8df0-dd800d0a9fef" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 나타나 이러한 증상때문에 신장암을 발견하게 되는 경우도 전체 환자의 30%에 이릅니다. </span></p><p id="SE-af799fd6-ceef-48eb-a8af-cf8b6a54d2b2" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-8e505b8a-1ed7-4607-8df0-dd800d0a9fef" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또한 신장암은 암세포가 생산하는 </span><span id="SE-510969f9-fa93-41fc-88eb-5b809bb73f09" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">특정 호르몬이 고혈압, 고칼슘혈증, 간기능의 이상</span><span id="SE-a016c9de-a723-4d41-b89f-c280e13e3ffc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;"> 등을 일으킬 수 있기 때문에 그러한 증상을 검사하던 중 종양이 발견되는 경우도 있습니다.</span><br></p><p id="SE-6743a056-5b1f-419a-9ec0-467bfe5dc54d" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-021fab4a-c37f-411d-95e5-3b32ce51978a" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-b40c0149-fe8d-4a4f-91e7-5cf0a5972695" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">신장암은 앞서 말씀드린 것처럼 이렇다 할 증상이 나타나지 않으며 이로 인해 다른 부위로 전이되는 경우가 많습니다. </span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-b40c0149-fe8d-4a4f-91e7-5cf0a5972695" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또 </span><span id="SE-d138cbfa-5284-479d-8290-9e9fb2f44e2e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">초기인 1기에 발견할 경우 5년 생존율이 90%</span><span id="SE-925c9996-cd62-46c8-a71d-cc9d64efe9e8" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">에 이르지만 </span><span id="SE-56ffc8cd-7515-4093-b879-8dd16b98f79d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">4기에 발견되면 최대 생존율 20%, </span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-56ffc8cd-7515-4093-b879-8dd16b98f79d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">평균 생존 기간이 약 2~3년</span><span id="SE-9ad9063d-9507-41f9-af9c-0ee8272609d2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;"> 정도로 예후가 매우 나쁘기 때문에 </span><span id="SE-e766c201-80f2-4fc0-9363-6134af558950" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">선제적이고 정기적인 건강 검진</span><span id="SE-6477f07c-f962-4401-ba7c-922f12f50074" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 통한 조기 발견이 중요합니다.</span><br></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-6477f07c-f962-4401-ba7c-922f12f50074" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암의 진단은 주로 건강검진을 통해 이루어지는 경우가 많습니다.</span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-a7a26291-6938-4e44-b832-ff46e60e4dfc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복부 초음파 검사</span><span id="SE-f744f7f0-c7dd-4aa0-9a98-2b7bec898c09" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">가 널리 이용되며, 초음파 검사에서 종양 물질이 발견될 경우 </span><span id="SE-0bcf5f52-8138-41ed-9ad3-7011cc867370" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복부 전산화단층촬영 (CT)</span><span id="SE-cde02bf5-0f80-4bfa-b9cb-4fce53fa36d2" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">으로 종양 물질에 대한 정확한 평가와 혈관, </span></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px;">신장 주위 임파선 및 주위 장기에 대한 전이 여부를 평가할 수 있습니다.</span><br></p><p id="SE-49fc3004-567c-413d-9c6c-d61bf4708999" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span style="font-family: NanumGothic; font-size: 16px;">또한 폐 전이 및 뼈 전이에 대한 검사도 고려해야 합니다.</span><br></p><p id="SE-c3d33ad0-86e5-4d2d-a769-689c1bb508e1" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="line-height: 2;"><span id="SE-2d012cb3-d3a6-4c60-8edf-8ac5c688c3ed" class="se-ff-nanumgothic se-fs19 __se-node"></span></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-a11y-title="인용구" style="font-size: medium; line-height: 2;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-25dcca27-be2c-44ac-ba5c-675d722212dd" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-521325b5-fe99-47f0-9001-208fa98dea87" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-55af4940-f0f1-4a29-8fad-03f1fa3b5630" class="se-ff-nanummyeongjo se-fs24 __se-node" style="font-family: NanumGothic; font-size: 24px; font-weight: bold;">l 신장암의 치료와 운동 요법</span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-df82fb2c-a7e6-4d1f-991f-39b2dde578e1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장암의 치료</span><span id="SE-f9296307-370c-49ca-a840-bc033382dcd5" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">는 다른 기관으로 </span><span id="SE-0ea68947-af4b-4bc2-8b2c-0257ba6d9e53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이된 경우</span><span id="SE-a9fa86f8-9e70-48c5-bbf9-077e86358b7d" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">와 </span><span id="SE-82a0e38e-c88c-45c9-ba81-c3ea334cd685" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">그렇지 않은 경우</span><span id="SE-aae2abc3-89a0-44c7-a5a0-5ef6f15b032a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로 나뉩니다. </span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-aae2abc3-89a0-44c7-a5a0-5ef6f15b032a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">전이되지 않았을 경우에는 </span><span id="SE-75021b1c-c48c-4b9f-88cd-da420ab4ed40" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">신장과 주위 정상 조직을 광범위하게 절제</span><span id="SE-51e7e3e4-69ea-411e-bfe4-fa57c8dfba46" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">하는 수술을 통해 치료합니다. </span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-51e7e3e4-69ea-411e-bfe4-fa57c8dfba46" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">종양이 크지 않을 때는 </span><span id="SE-d121ba06-6ba2-4859-9ece-2a21a5eec316" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">복강경을 이용해 수술</span><span id="SE-4557860f-5431-4303-975a-64058a574bc9" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">하는 경우도 있으며, 최근에는 </span><span id="SE-632c9fca-c1c3-4f49-b98b-e512f8473b8f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로봇수술</span><span id="SE-02280a90-f8c3-4236-a774-f01cb3a87d7c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">역시 각광받고 있습니다. </span></p><p id="SE-a3b7f315-d1f5-408b-a0e9-8c0ff392e23c" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span id="SE-02280a90-f8c3-4236-a774-f01cb3a87d7c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">환자의 나이가 </span><span id="SE-60967970-6cdd-4abe-b356-955ce9d0290c" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">젊거나 종양 크기가 작을 때는 신장 부분 절제술</span><span id="SE-fefa0f26-6955-45bc-8d3e-bbedb19fc518" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">을 시행하기도 합니다.</span><br></p></div></div></div></div></div></div><div class="se-component se-text se-l-default" id="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-compid="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-a11y-title="본문" style="font-size: medium; line-height: 2;"><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-cf4ba76f-d1a2-4462-94b2-47f6317dac1e" data-direction="top" style="line-height: 2;"><div class="se-section se-section-text se-l-default se-is-focused" style="line-height: 2;"><div id="SE-1b4920f2-c4e6-459b-9b87-eb8359d3f69e" class="se-module se-module-text __se-unit" style="line-height: 2;"><p id="SE-20d5df14-7534-4da2-ae59-a552167e2f8d" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9daa0bc4-d7c4-4e9e-8fca-9100a176ac78" class="se-ff-nanumgothic se-fs19 __se-node"></span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9c067790-5997-4d4d-b420-82a4478a22ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">신장암이 </span><span id="SE-a3f6f3c3-04a0-4885-9101-016b8b428448" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">한 장기로만 전이된 경우에는 종양만 제거</span><span id="SE-39b3691e-6f56-4aa6-b4c3-b1c7a897a183" class="se-ff-nanumgothic se-fs19 __se-node" style="font-family: NanumGothic; font-size: 16px;">하는 것이 도움이 되기도 합니다. </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-39b3691e-6f56-4aa6-b4c3-b1c7a897a183" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이외 치료 방법은 </span><span id="SE-dfb0acf3-8512-43cb-a107-9332cde99e1f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">면역요법, 호르몬요법, 항암 화학요법, 방사선요법</span><span id="SE-f6e08743-70a5-4dc2-b6d9-bf9a18eb42ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">등이 있습니다. </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-f6e08743-70a5-4dc2-b6d9-bf9a18eb42ad" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또 예방과 치료 모두에 있어 </span><span id="SE-1fd981eb-e07e-41bc-9fc6-83c97f0bc4bd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">운동요법의 중요성</span><span id="SE-9251053c-c147-424b-83d3-e5b6ee317c53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이 강조되고 있는데, 이는 2020년 세계 신장암의 날의 주제로 나타났을 정도입니다. </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-9251053c-c147-424b-83d3-e5b6ee317c53" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">당시 </span><span id="SE-cda67035-6bc0-4844-b343-90634f1535f6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">주제는 ‘건강을 위한 운동, 우리 함께 이야기해봐요.’</span><span id="SE-2ace55d9-f612-48f9-8e6d-d69c88e23315" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">로, 신장암 예방 및 예후 개선에 있어 신체 활동의 중요성을 알리기 위한 캠페인이었습니다. </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-2ace55d9-f612-48f9-8e6d-d69c88e23315" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">국제신장암연합의 자료에 따르면 신체적으로 활동적인 것만으로 신장암 </span><span id="SE-b8f00b1e-5537-4144-a7bd-7ef4a7d9f3b7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">발생 위험을 최대 22%까지 줄일</span><span id="SE-3fa57bb1-b66a-4f20-999b-0c5fd7bc00cd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;"> 수 있으며, </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-3fa57bb1-b66a-4f20-999b-0c5fd7bc00cd" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이미 발병한 이유에도 </span><span id="SE-51528ee9-75ac-4cbc-aa8c-d725d1a08b1f" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">적당한 신체활동을 통해 치료 예후를 최대 15% 향상</span><span id="SE-e91dab7b-81b7-4cd4-81b5-f64aed4a7de1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">시킬 수 있습니다.</span><br></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-e91dab7b-81b7-4cd4-81b5-f64aed4a7de1" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">또한 미국 로스웰파크 암연구소 연구팀의 연구에 따르면 운동을 전혀 하지 않는 사람의 경우 신장암의 발병 확률이 </span><span id="SE-77319e4c-03ca-4dbd-8303-c9e0a1974196" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">최고 77%</span><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">까지 치솟았습니다.</span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">정상 체중을 유지하더라도 신체 활동이 없을 경우 암 발병 위험이 유의미하게 높아진다는 것입니다. </span></p><p id="SE-36451202-e0e9-481a-bb1a-a542a53f3a9e" class="se-text-paragraph se-text-paragraph-align-justify" style="line-height: 2;"><span id="SE-27b31165-3565-422e-bc95-82ea2fb9c59e" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">따라서 신장암 치료와 예방 모든 측면에서 운동요법은 </span><span id="SE-c61e6bcb-2015-4545-a62b-26f4e3529aca" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">생활 속에서 실천이 가능한 가장 효과적인 방법</span><span id="SE-680c2c35-3fd2-4ab8-b0db-66e723cbb6ca" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: 16px; font-family: NanumGothic;">이라고 볼 수 있습니다.</span><br></p></div></div></div></div></div><div class="se-component se-quotation se-l-default" id="SE-6196c708-1fbc-449d-be48-024032da1549" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-a11y-title="인용구" style="font-size: medium; line-height: 2;"><button class="se-component-edge-button se-component-edge-button-top __edge-area" type="button" tab-index="-1" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-direction="top"></button><div class="se-component-content" style="line-height: 2;"><div class="se-drop-indicator" data-unitid="" data-compid="SE-6196c708-1fbc-449d-be48-024032da1549" data-direction="top" style="line-height: 2;"><div class="se-section se-section-quotation se-l-default se-section-align-left __se-unit se-is-selected se-is-block-selected" style="line-height: 2;"><div class="se-quotation-container" style="line-height: 2;"><div id="SE-ddc7ce83-c901-4d77-8ba4-497310ad8d74" class="se-module se-module-text __se-unit se-quote" style="line-height: 2;"><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: 16px; font-family: NanumGothic;">﻿</span><img src="/uploads/editor/883d02238cf434d3c5e5f56959b813bc.png" data-filename="메디인병원_프로필_오영승_세로.png" style="width: 800px;"></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><b>[메디인병원 신장내과 오영승 진료과장]​</b></p><p id="SE-1756c69b-2e4a-4f80-960c-e0df87c1fe9b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-d584e198-1403-41fc-b43b-f7a6cbb8cca2" class="se-ff-nanumgothic se-fs19 __se-node">건양대학교 의과대학 졸업</span></p><p id="SE-1f31128e-f1b7-42f8-9001-3ee847f856af" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-6c79a41e-5a1f-4f5b-83e8-47e60b9269be" class="se-ff-nanumgothic se-fs19 __se-node">前 순천향대학교 부천병원 신장내과 임상강사</span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4ae29ba4-f296-48fb-a46a-d1083f528cf9" class="se-ff-nanumgothic se-fs19 __se-node">가톨릭중앙의료원 전공의</span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span class="se-ff-nanumgothic se-fs19 __se-node"><br></span></p><p id="SE-48447e7f-1c5a-44de-af29-d4cf8caead5b" class="se-text-paragraph se-text-paragraph-align-center se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4ae29ba4-f296-48fb-a46a-d1083f528cf9" class="se-ff-nanumgothic se-fs19 __se-node"><br></span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-c43feac2-b1a3-48bb-8621-3abd353ce4d8" class="se-ff-nanumgothic se-fs19 __se-node">메디인병원은 신장내과 전문의인 </span><span id="SE-a1c1c549-90e2-44a5-867a-08ac26453fee" class="se-ff-nanumgothic se-fs19 __se-node"><b>오영승 진료과장</b></span><span id="SE-f92a77bf-c516-4816-8643-1c221f9dbff4" class="se-ff-nanumgothic se-fs19 __se-node">을 주재로 </span><span id="SE-bdc0724a-9908-41d7-8756-9d9f3f781806" class="se-ff-nanumgothic se-fs19 __se-node"><b>신장내과</b></span><span id="SE-38285bed-a6e5-44dd-9a29-e74af4ca3b1c" class="se-ff-nanumgothic se-fs19 __se-node">와 </span><span id="SE-805d943f-9fdf-4943-96cd-402720c53d5d" class="se-ff-nanumgothic se-fs19 __se-node"><b>인공신장클리닉</b></span><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node">을 운영하고 있습니다. </span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">신장내과와 인공신장클리닉에서는 최신식 장비와 시설로 신부전을 비롯한 신장 관련 질환의 진단과 치료 등 의료서비스를 제공하고 있습니다. </span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-4cc79e66-fa75-46fa-b6c9-777489de6139" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">특히 지난 4월 신설된 </span><span id="SE-0dd8bf7a-1ae2-476e-9c6d-dfb93797f0a6" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>인공신장클리닉</b></span><span id="SE-d0b1290f-4965-4565-b2c8-a23fb224eddc" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">은 </span><span id="SE-431e4fee-d029-4048-bfe3-b0f380332849" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>만성신부전증 신장질환 환자</b></span><span id="SE-b8675c2c-18ea-4566-8e01-d860477bf9c7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">를 대상으로 증상 단계에 따라 </span></p><p id="SE-3fbc72cf-c930-4211-9f4f-707ae25ec658" class="se-text-paragraph se-text-paragraph-align-justify se-is-text-paragraph-block-selected" style="font-size: medium; line-height: 2;"><span id="SE-ed4b95f3-00f5-4d4f-8a03-cdec04b69b5a" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>식이요법부터 혈액 투석, 복막 투석 치료</b></span><span id="SE-e1958b46-a029-4825-b22d-4dd5d135fb47" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">와 </span><span id="SE-910ba600-3073-40b8-b24b-357b679720d7" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;"><b>관련 합병증 치료</b></span><span id="SE-d3b0cedc-14a7-47af-84df-e84354f8e519" class="se-ff-nanumgothic se-fs19 __se-node" style="font-size: medium;">를 함께 진행합니다.</span><br></p><p class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><img src="/uploads/editor/855a9ad43e2aa064eb6c5b380d1e1c95.jpg" data-filename="kite-1666816_1920.jpg" style="width: 25%;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><br></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">﻿</span><span data-input-buffer="INPUT_BUFFER_DATA;Mozilla%2F5.0%20(Windows%20NT%2010.0%3B%20Win64%3B%20x64)%20AppleWebKit%2F537.36%20(KHTML%2C%20like%20Gecko)%20Chrome%2F106.0.0.0%20Safari%2F537.36;blog.naver.com" style="font-size: medium;"></span><span style="font-size: medium;">지금까지 세계 신장암의 날을 맞아 신장암과 조기 발견, 운동요법의 중요성에 대해 전해드렸습니다. </span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">신장암은 초기에 별 다른 증상이 없어 발견하기 힘들어 뒤늦게 발견할 경우 생존률이 낮지만 선제적인 건강 검진을 통해 조기에 발견할 경우 생존률이 매우 높습니다. </span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;">이러한 신장암의 조기 발견을 위한 건강 검진과 꾸준한 생활 속 운동요법을 통해 건강한 삶을 보내시길 바랍니다.</span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span></p><p id="SE-04ae36cb-8c5e-4662-915f-5641ba517761" class="se-text-paragraph se-text-paragraph-align-center" style="line-height: 2;"><span style="font-size: medium;"><br></span><br></p></div></div></div></div></div></div></div></div></div></div></div></div>', 110, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 22:49:36', '2022-10-19 10:44:33', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(21, NULL, 2, '파주 메디인병원, 지역 최초 민간종합병원으로 개원', '관리자', NULL, NULL, 1176, '59.5.161.67', 0, 0, 0, NULL, '2022-09-27 22:51:38', '2022-09-27 22:51:38', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', '뉴스1', 'https://www.news1.kr/articles/4667526', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(22, NULL, 2, '파주 메디인병원, 민간종합병원 승격 기념 신축 개원식 진행', '관리자', NULL, NULL, 1179, '59.5.161.67', 0, 0, 0, NULL, '2022-09-27 22:53:55', '2022-09-27 22:53:55', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', '헬스인뉴스', 'http://www.healthinnews.co.kr/news/articleView.html?idxno=29681', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(23, NULL, 4, '[병원시설 안내] 메디인 병원에서 진료 가능한 12과목 소개(와과계,내과계,진료지원계,특수기관)', '관리자', NULL, '<p>안녕하세요,메디인병원입니다.</p><p>환자분들이 겪고 있는 질환과 문제를 보다 정밀하고 효과적으로 진료하기 위해 메디인 병원은 다양한 과목을 진료하고 있습니다.</p><p>현재 저희 메디인 병원은 21명의 전문의가 12과목을 담당하고 있으며, 1월24일부터 신설되는 심장내과를 필두로 3월2일에는 42명의 전문의가 재활의학과의 산부인과 등을 포함해 19과목을 담당할 예정입니다.</p><p>오늘은 현재 진료 가능한 12과목을 크게 외과계열,내과계열,진료지원계열,특수기관으로 나눠 설명하고자 합니다.</p>', 60, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 22:58:39', '2022-10-19 10:45:31', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(24, NULL, 4, '[병원시설 안내] 생명유지에 중요한 심장, 심혈관센터(심장내과) 새롭게 개설', '관리자', NULL, '<p>01월 24일부터 메디인 병원에 심혈관 질환을 담당하는 심혈관센터가 새롭게 개설되었습니다.</p><p>현재 전문의 윤성규 과장이 심혈관센터를 담당하여 고혈압,고지혈증,심부전,부정맥 등 심혈관 관련 진료 및 의료서비스를 제공하고 있습니다.</p><p>오늘은 심혈관 질환 및 심혈관센터에 대해 소개하고자 합니다.</p>', 64, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 23:00:10', '2022-10-19 10:45:25', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(25, NULL, 4, '[병원시설 안내] 여성의 삶에 밀접한 영향, 산부인과 신설 예정', '관리자', NULL, '<p>저희 파주 메디인병원은 3월2일에 민간종합병원으로 개원하면서 기존에 개설된 진료 과목에 산부인과, 신장내과등을 더해 총 19개의 과목을 진료할 예정입니다.</p><p>오늘은 신설될 진료 과목 중 산부인과에 대해 소개드리고자 합니다.</p>', 71, '112.161.27.82', 0, 0, 0, NULL, '2022-09-27 23:01:22', '2022-10-19 10:45:13', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'N', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(26, NULL, 4, '만 65세 이상 독감 무료 예방접종 ', '관리자', NULL, '<p><img src="/uploads/editor/2204ffbff862c47c4208dc7fa8380362.png" style="width: 50%;" data-filename="독감예방접종.png"><br></p>', 906, '112.161.27.82', 0, 0, 0, NULL, '2022-10-19 10:23:58', '2022-10-19 10:23:58', NULL, NULL, 'N', NULL, 'Y', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
