	(27, NULL, 1, '만 65세 이상 독감 무료 예방접종 ', '관리자', NULL, '<p><img src="/uploads/editor/ef66e15ff0c230ee5fbc653ab3c6d877.png" style="width: 50%;" data-filename="독감예방접종.png"><br></p>', 2367, '112.161.27.82', 0, 0, 0, NULL, '2022-10-19 10:25:11', '2023-01-02 11:59:50', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(28, NULL, 1, '메디인병원에서 모의 소방훈련', '관리자', NULL, '<p style="line-height: 2;"><b><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">지난주 금요일~</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">메디인병원에서 모의 소방훈련이 진행되었습니다~</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">바쁘신 와중에도 훈련에 참여해 주신 직원 여러분들 고생 많으셨습니다^^</span></b></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><img src="/uploads/editor/a2de9063e733405636eb3419d026a951.jpg" style="width: 450px;" data-filename="모의소방훈련-1.jpg"></p><p><img src="/uploads/editor/5edda0a254c27d383bc60bd1dd60c4c7.jpg" style="width: 450px;" data-filename="모의소방훈련-2.jpg"></p><p><img src="/uploads/editor/2082473eb008d94801fb14c135ff2c14.jpg" style="width: 450px;" data-filename="모의소방훈련-3.jpg"></p><p><img src="/uploads/editor/48f2ce07a3cb6faecdf3ad0c4173ec7c.jpg" style="width: 450px;" data-filename="모의소방훈련-4.jpg"></p><p><img src="/uploads/editor/560309cb8d248384d34a9e98999eac31.jpg" style="width: 450px;" data-filename="모의소방훈련-5.jpg"></p><p><img src="/uploads/editor/83e86239ac7d2d9deb1d478b65f03ecd.jpg" style="width: 450px;" data-filename="모의소방훈련-6.jpg"></p><p><img src="/uploads/editor/249218c20d47e7f9b98f619b6dc50e1d.jpg" style="width: 450px;" data-filename="모의소방훈련-9.jpg"></p><p><img src="/uploads/editor/5f3bedb3c8f5e81e0233c91830a22afa.jpg" style="width: 450px;" data-filename="모의소방훈련-10.jpg"></p><p><img src="/uploads/editor/b1e48d63429cced4ebb09c88d6359c1a.jpg" style="width: 450px;" data-filename="모의소방훈련-8.jpg"></p><p><img src="/uploads/editor/a2e2d2e5339411dbbded986cffe37205.jpg" data-filename="모의소방훈련-7.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 450px;"></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>', 1292, '112.161.27.82', 0, 0, 0, NULL, '2022-10-20 12:09:08', '2022-10-20 12:09:08', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(29, NULL, 1, '메디인 병원 & 금촌소방서와 함께하는, 2022년 소방훈련!', '관리자', NULL, '<p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><b style="color: rgb(115, 24, 66);"><span style="font-size: 16px;">메디인 병원</span><span lang="EN-US" style="font-size: 16px;"> & </span><span style="font-size: 16px;">금촌소방서와 함께하는</span><span lang="EN-US" style="font-size: 16px;">, 2022</span><span style="font-size: 16px;">년 소방훈련</span><span lang="EN-US" style="font-size: 16px;">!<br><br></span></b></p><p class="MsoNormal"><span style="font-size: 14px;">메디인병원은</span><span lang="EN-US" style="font-size: 14px;"> \'</span><span style="font-size: 14px;">화재에 따른 위기대처 능력 강화</span><span lang="EN-US" style="font-size: 14px;">\'</span><span style="font-size: 14px;">를 위해 지난</span><span lang="EN-US" style="font-size: 14px;"> 20</span><span style="font-size: 14px;">일 금촌소방서와 함께 합동 소방훈련을 실시하였습니다</span><span lang="EN-US" style="font-size: 14px;">. </span></p><p class="MsoNormal"><span style="font-size: 14px;">이번 훈련은 병동 내 화재 발생상황을 가정하여 층별 환자 대피요령뿐만 아니라 소화전과 소화기를 이용한 화재 진압방법을\r\n숙지할수 있는 중요한 시간이었습니다</span><span lang="EN-US" style="font-size: 14px;">. </span></p><p><span style="font-size: 14px;">\r\n\r\n\r\n\r\n\r\n\r\n</span></p><p class="MsoNormal"><span style="font-size: 14px;">메디인 병원은 지속적인 훈련과 교육을 통해 위기 대응 능력을 강화하고 재난재해 상황으로부터 안전한 병원을 만들수\r\n있도록 최선을 다하겠습니다</span><span lang="EN-US" style="font-size: 14px;">.</span></p><p class="MsoNormal"><span lang="EN-US"><br></span></p><p class="MsoNormal"><span lang="EN-US"><img src="/uploads/editor/0076ea296962de7f9b9a693dd91bb1f7.jpg" data-filename="1013소방훈련1.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 676.75px;"></span></p><p class="MsoNormal"><span lang="EN-US"><br></span></p><p class="MsoNormal"><span lang="EN-US"><img src="/uploads/editor/ed9e2588d8f7824f8de8b32182a356e9.jpg" data-filename="20221020_150132.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"><br></span></p><p class="MsoNormal"><br></p><p class="MsoNormal"><span lang="EN-US"><img src="/uploads/editor/137f0014e03c0ddcc7c50b844bd83428.jpg" data-filename="20221020_150205.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"><br></span></p><p class="MsoNormal"><span lang="EN-US"><br></span></p><p class="MsoNormal"><img src="/uploads/editor/0fb24be912c197ab1f7f68f89e5fd08a.jpg" style="width: 800px;" data-filename="20221020_150322.jpg"></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/baff75a4165c76d23ed8fa9465c2e990.jpg" style="width: 800px;" data-filename="20221020_150227.jpg"></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/06626055e08ecf1ab6cd5ee904951007.jpg" data-filename="20221020_150349.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/1679d5fffefd9c5da0bf31ff6147247f.jpg" data-filename="20221020_150415.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/6cd386f91f5990abfc13847a5e13004c.jpg" data-filename="20221020_150601.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/fdaddf7bba9a4db72c00bfedb7026392.jpg" data-filename="20221020_150802.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/823a15fc1e22391e10d2cefe96fea90a.jpg" data-filename="20221020_150945.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/9e0e358b3330e9697da76655dfd3da70.jpg" data-filename="20221020_150331.jpg" style="font-size: 13px; font-family: inherit; letter-spacing: -0.26px; width: 800px;"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><img src="/uploads/editor/b