ass="MsoNormal"><span lang="EN-US"><br></span></p>', 1448, '112.161.27.82', 0, 0, 0, NULL, '2022-10-25 17:25:21', '2022-12-06 13:48:44', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
