	(30, NULL, 1, '경동대학교 간호대학 취업설명회~!!!!', '관리자', NULL, '<p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p style="line-height: 3;"><b><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 10월 26일~</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">경동대학교 간호대학에서 취업설명회가 있었습니다~</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">졸업을 앞둔 경동대학교 간호대학 재학생들과의 만남을 통해 실질적인 병원 근무환경에 대한 정보를 제공할 수 있는 뜻 깊은 자리였답니다^^</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">경동대 간호대학 재학생 여러분~</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원에서 다시 만나요~~♥</span></b><br></p><p><br></p><p><br><img src="/uploads/editor/467cb3678982dd9ce3d9c6dc15523425.jpg" data-filename="경동대취업박랍회0.jpg" style="font-size: 13px; letter-spacing: -0.26px; width: 800px;"><br></p><p><img src="/uploads/editor/0560e2d3b566af27db93f1246d2a6b20.jpg" style="width: 800px;" data-filename="경동대취업박랍회2.jpg"><img src="/uploads/editor/f00bad7a4ba092fc935e94ca47c2acd7.jpg" style="width: 800px;" data-filename="경동대취업박랍회1.jpg"><img src="/uploads/editor/4d0716bf26a85b3bff988edc2725a468.jpg" style="width: 800px;" data-filename="경동대취업박랍회3.jpg"><img src="/uploads/editor/438ff07fa0ae86603f125b50d7b1f426.jpg" style="width: 800px;" data-filename="경동대취업박랍회4.jpg"><img src="/uploads/editor/937d83e3658557193f1ed35ef433a618.jpg" style="width: 800px;" data-filename="경동대취업박랍회5.jpg"><br></p>', 1349, '112.161.27.82', 0, 0, 0, NULL, '2022-10-31 13:27:27', '2022-12-06 13:49:19', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
