	(31, NULL, 2, '메디인병원, 파주 최초 민간종합병원 승격!', '관리자', NULL, NULL, 1368, '112.161.27.82', 0, 0, 0, NULL, '2022-11-01 13:38:53', '2022-12-06 12:03:18', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', '서울경기케이블TV', 'https://youtu.be/dIMnwmQBkd8', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
