	(33, NULL, 1, '2022 국가건강검진 무료혜택!', '관리자', NULL, '<p><br></p><p>2022 국가건강검진 무료혜택!<br></p><p><br></p><p><img src="/uploads/editor/3d5cdafcf85255d431c0f20161449714.jpg" style="width: 50%;" data-filename="2022국가건강검진 copy.jpg"><br></p>', 2819, '112.161.27.82', 0, 0, 0, NULL, '2022-11-04 16:48:43', '2023-01-02 11:57:43', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
