	(34, NULL, 2, '메디인병원 개원방송', '관리자', NULL, NULL, 1294, '112.161.27.82', 0, 0, 0, NULL, '2022-11-07 11:28:43', '2022-11-07 11:28:43', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', '해피코리아', 'https://www.youtube.com/watch?v=yUVUNp8DcYI', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(35, NULL, 1, '국내최초 모바일 신분증을 연계한 키오스크 도입~!', '관리자', NULL, '<p><span style="background-color: rgb(206, 0, 0); color: rgb(255, 255, 255);"><span style="font-family: inherit; letter-spacing: -0.02em;"><br></span></span></p><p><span style="background-color: rgb(206, 0, 0); color: rgb(255, 255, 255); font-weight: bold;"><span style="font-family: inherit; letter-spacing: -0.02em; font-size: 16px;">메디인 병원,</span><br></span></p><p style="line-height: 2;"><span style="color: rgb(255, 255, 255); font-weight: bold;"><span style="background-color: rgb(206, 0, 0); font-size: 16px;" segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">국내최초 모바일 신분증을 연계한 키오스크 도입~!</span><br style="" segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""></span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">메디인 병원은 국내최초로 모바일 신분증을 연계한 키오스크를 도입하였습니다.</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">점자기능이 탑재되어 있어 장애인과 비장애인이 공용으로 사용가능합니다.</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">메디인 병원은 차별 없는 양질의 의료 서비스 제공을 위해 지속적으로 노력하고 있습니다. ^^</span><br style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""></p><p style="line-height: 2;"><br></p><p style="line-height: 2;"><br></p><p style="line-height: 2;"><img src="/uploads/editor/588ccb73fa93877f7e6ba4bf8f7e74ee.jpg" style="width: 800px;" data-filename="제목을 입력해주세요_-001.jpg"><br></p>', 2604, '112.161.27.82', 0, 0, 0, NULL, '2022-11-10 10:13:50', '2022-12-06 13:49:34', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
