	(67, NULL, 1, '메디인 병원 참나무 요양병원 협약식', '관리자', NULL, '<p style="line-height: 1.6;">지난 2월 1일 메디인 병원과 참나무 요양병원의 협약식이 있었습니다. </p><p style="line-height: 1.6;">이번 협약 체결을 통해 참나무 요양병원과 메디인병원 환자들에게 더 나은 의료서비스를 제공할수 있을것으로 기대합니다. </p><p style="line-height: 1.6;">파주 최초 민간 종합병원 메디인 병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공하고 있으며, </p><p style="line-height: 1.6;">경기북부 최고의 종합병원으로 성장해 나갈 수 있도록 최선을 다하고 있습니다.</p><p><br></p><p><br></p><p></p><p></p><p><br></p><p></p><p></p><p><img src="/uploads/editor/51827985e9af2d74c378dcce73e45252.jpg" data-filename="DSC_1184.JPG" style="width: 800px;"></p><p><img src="/uploads/editor/6564cd8e1785aef7818aff18c238cdae.jpg" data-filename="DSC_1157.JPG" style="width: 800px;"></p><p><img src="/uploads/editor/1656f4dedabf3517ce46e557ab980495.jpg" data-filename="DSC_1173.JPG" style="width: 800px;"></p><p><img src="/uploads/editor/383a48e6c03b65f0f1817bfd6d41e189.jpg" data-filename="DSC_1188.JPG" style="width: 800px;"><br></p>', 2250, '112.161.27.82', 0, 0, 0, NULL, '2023-02-07 17:36:55', '2023-02-22 13:28:52', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
