	(72, NULL, 1, '메디인 병원, 동국대 병원 간담회 개최!', '관리자', NULL, '<p><font color="#262626">﻿</font></p><p><font color="#262626">안녕하세요~</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">파주종합병원 메디인 병원입니다.</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">지난 2월 20일 메디인 병원과 동국대 병원간의 간담회가 진행되었습니다.</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">이번 간담회는 흉부외과와 심장내과 환자 진료의 편의성을 확대하고</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">보다 빠르고 정확한 전원과 치료를 위한 \'핫라인 구축\'에 대한 노의가 이루어 졌습니다.</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">메디인 병원과 동국대 병원은 주기적인 간담회를 통해 지역주민의 건강 향상을 위한 다양한 프로그램을 진행할 예정입니다.</font></p><p><font color="#262626"><br></font></p><p><font color="#262626">﻿</font></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br></span></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br></span></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br></span></p><p><span style="color: rgb(38, 38, 38); font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br></span><img src="/uploads/editor/f8a72c41f32406e862874945822d7f48.jpg" data-filename="동국대3.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/9ea199b0f3fa91bcc984f6ee3c7bc1c2.jpg" data-filename="동국대1.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/f488880db553da7cf1874445679c6767.jpg" data-filename="동국대2.jpg" style="width: 800px;"><br></p>', 2034, '112.161.27.82', 0, 0, 0, NULL, '2023-02-24 14:17:40', '2023-02-24 14:24:00', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
