	(74, NULL, 1, '경기도 성실납세자 종합검진 의료비 지원~', '관리자', NULL, '<p><br></p><p><br></p><p>메디인 병원은 \'경기도 성실납세자\'를 대상으로 본인 및 직계가족의 종합건강검진 의료비를 지원합니다~</p><p>성실납세자 지원을 받기 위해서는 성실납세자를 증명하는 인증서 등 증명자료가 필요하답니다~^^</p><p><br></p><p><br></p><p><img src="/uploads/editor/08eaa8773a4ddcf6477b23bdc6e0af94.jpg" data-filename="성실납세자1.jpg" style="width: 800px;"></p><p></p><p><img src="/uploads/editor/3d5b9773732a217d4bb9d3852ed13625.jpg" data-filename="성실납세자2.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/5221100902142c31d63cdc8b26aa61db.jpg" data-filename="성실납세자3.jpg" style="width: 800px;"><br></p><p><br></p>', 2200, '112.161.27.82', 0, 0, 0, NULL, '2023-03-03 16:13:22', '2023-03-03 16:13:22', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
