	(80, NULL, 1, '메디인병원 소방안전교육 실시!', '관리자', NULL, '<p><br></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 \'화재에 따른 위기대처 능력 강화\'를 위해 지난 4월 7일 소방안전교육이 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">이번교육은 메디인병원 전직원을 대상으로 부서별로 진행됩니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">바쁘신 와중에 참여해 주신 모든 분께 감사드립니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인 병원은 지속적인 훈련과 교육을 통해 위기 대응 능력을 강화하고 재난재해 상황으로부터 안전한 병원을 만들수 있도록 최선을 다하겠습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">▶운정/파주종합병원, 메디인병원</span></p><p><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">▶파주시 금릉역로 190</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">▶문의) 1566-1991</span><br></p><p><br></p><p><br></p><p><img src="/uploads/editor/5800970268303086ed7fcdfcf2df705d.jpg" data-filename="소방안전훈련.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/227cd528e6a5212ca9e7656f120ab023.jpg" data-filename="소방안전교육2.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/1f5881453de2cd7e0ebd4d5b001ca933.jpg" data-filename="소방안전교육1.jpg" style="width: 600px;"><br></p><p></p><p><br></p><p></p><p><br></p><p><br></p><p></p><p><br></p><p><br></p><p><br></p>', 2839, '112.161.27.82', 0, 0, 0, NULL, '2023-04-11 15:21:22', '2023-05-02 14:10:19', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
