	(81, NULL, 2, '근육 떨리고 힘 빠지는 증상…‘루게릭병’일 확률은?', '관리자', NULL, NULL, 1082, '112.161.27.82', 0, 0, 0, NULL, '2023-04-11 15:23:52', '2023-05-09 14:36:45', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, 'FID00000034', NULL, 'Y', '하이닥', 'https://www.hidoc.co.kr/healthstory/news/C0000781422', NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
