	(114, NULL, 7, '메디인 병원 성인병 클리닉', '관리자', NULL, '<p><img src="/uploads/editor/eed37ac5385b2e316cc5a21f1f6acfe6.jpg" data-filename="성인병클리닉1.jpg" style="width: 50%;"></p><p><br></p><p><br></p><p><img src="/uploads/editor/1e05efc078aec872e3c9b205f444f210.jpg" data-filename="성인병클리닉2.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/de2bfe1862ad7b7fabf463a03b3c5e97.jpg" data-filename="성인병클리닉3.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/2f846ea9cc479c337398854cfc85843c.jpg" data-filename="성인병클리닉4.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/486563aaaf5a8cd51d3e4db70a73ca3a.jpg" data-filename="성인병클리닉5.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/b12acb1a32c7bf00583aabb990a62997.jpg" data-filename="성인병클리닉6.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/98c2380ac402b79279dc090ebd5b1865.jpg" data-filename="성인병클리닉7.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/7eb11a820083daa1ec0f0cf95018c536.jpg" data-filename="성인병클리닉8.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/b0acf1f2217017ec654a35df0c98f51e.jpg" data-filename="성인병클리닉9.jpg" style="width: 800px;"><br></p>', 1710, '112.161.27.82', 0, 0, 0, NULL, '2023-06-07 11:54:50', '2023-06-07 11:54:50', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000050', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(115, NULL, 1, '심폐소생술(CPR) 및 자동 제세동기(AED) 교육', '관리자', NULL, '<p><br></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 6월 15일 메디인병원 전직원 대상으로 심폐소생술(CPR) 및 자동 제세동기(AED) 교육이 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">이번 교육은 재해재난 상황 시 생길 수 있는 응급 상황에 보다 빠르고 정확한 응급 처치를 할 수 있는 능력을 함양하기 위해 마련되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 재해재난 상황에서 모든직원이 신속하게 대처할 수 있도록 주기적인 교육을 진행할 예정입니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">바쁘신 와중에 참석해 주신 많은 직원여러분과 교육을 진행해 주신 응급의학과 최규만 과장님 감사드립니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><br></p><p><br></p><p><img src="/uploads/editor/6e526a96de0db826349b721cc40aec84.jpg" data-filename="cpr1.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/a64de7d4cfbb856a726b0779fd415dc7.jpg" data-filename="cpr2.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/3dccb3cc969a474a13d541b07cc6791a.jpg" data-filename="cpr3.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/678fc569a70d266a18c5959409e6a72d.jpg" data-filename="cpr4.jpg" style="width: 50%;"><br></p>', 4565, '112.161.27.82', 0, 0, 0, NULL, '2023-06-16 14:29:44', '2023-06-28 16:54:15', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, 'FID00000051', 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
