	(117, NULL, 7, '내시경적 역행성 담췌관조영술 (ERCP)', '관리자', NULL, '<p><img src="/uploads/editor/ed21f4e20d70b9fd6dc380cc4e27c866.jpg" data-filename="ERCP1.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/ea36d82dc6b3b4f00b35b0b4c2a432aa.jpg" data-filename="ERCP2.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/2d817e58afa15ed0442dcbdbe30c129b.jpg" data-filename="ERCP3.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/62d66cec99ac78beb1c1ee1f7d94d251.jpg" data-filename="ERCP4.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/b02560cb5693c24ed3938e50b4dd5c35.jpg" data-filename="ERCP5.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/1a5fb82cf0f373173656ebf15bef3a06.jpg" data-filename="ERCP6.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/9c8f1025da471f28027005e75bf9a4e2.jpg" data-filename="ERCP7.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/c95306a80c763b7174d3d98d5386d0a3.jpg" data-filename="ERCP8.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/422ba17626fabfc42473fd7eec620e1e.jpg" data-filename="ERCP9.jpg" style="width: 50%;"><br></p>', 1915, '112.161.27.82', 0, 0, 0, NULL, '2023-06-21 16:59:09', '2023-06-21 16:59:09', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000053', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
