	(118, NULL, 7, '함께하는 감염예방, 깨끗한 손씻기', '관리자', NULL, '<p><br></p><p><br></p><p><img src="/uploads/editor/0f571e08ebed7b806ae1b12c6e59eec4.png" data-filename="001.png" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/313c819799a702b1fb303afca37e8f5b.png" data-filename="002.png" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/7dd47bf85abc5fed674613f9612c80c5.png" data-filename="003.png" style="width: 50%;"></p><p><br></p><p><br></p>', 2484, '112.161.27.82', 0, 0, 0, NULL, '2023-06-23 13:21:09', '2023-06-23 13:21:09', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000054', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
