	(119, NULL, 1, '2023년 유행성 감염병 대응 훈련', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 6월 23일 \'2023년 유행성 감염병 대응 훈련\'이 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">이번 모의훈련은 언제 발생할지 모르는 유행성 감염병 발생 상황에 따른 대응체계를 확립하는 동시에 위기상황에 대한 능력을 강화하기 위해 마련되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 주기적인 훈련을 통해 유행성 감염병 의심 환자가 병원에 내원 했을 때 신속하고 적절하게 대응할 수 있도록 최선의 노력을 다하고 있습니다.</span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><img src="/uploads/editor/ae17ae02574dd8740cd37e5af92b0157.jpg" data-filename="감염대응훈련1.jpg" style="width: 50%;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><img src="/uploads/editor/c0275efe15154fb9d7db6443f95c56f2.jpg" data-filename="감염대응훈련2.jpg" style="width: 50%;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span><br></p>', 2841, '112.161.27.82', 0, 0, 0, NULL, '2023-06-27 15:33:15', '2023-06-28 16:54:44', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
