	(122, NULL, 7, '우리병원을 안전하게 이용하는 방법을 알려드릴게요!', '관리자', NULL, '<p><img src="/uploads/editor/996829701e05f7ced9278cfd48eff0d7.jpg" data-filename="우리병원을 안전하게1.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/cc1214813682fb3ab2ebf51307860122.jpg" data-filename="우리병원을 안전하게2.jpg" style="width: 50%;"><br></p>', 1440, '112.161.27.82', 0, 0, 0, NULL, '2023-07-06 14:16:58', '2023-07-06 14:16:58', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, NULL, 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000057', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
