	(123, NULL, 1, '응급 상황을 대비한 심폐소생술 교육', '관리자', NULL, '<p><br></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">지난 7월 6일 메디인 병원은 파주시지역사회보장협의체 건강분과 활성화 사업의 일환으로 \'응급 상황을 대비한 심폐소생술 교육\'을 진행하였습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">이번 교육은 독거노인, 장애인 등 건강에 문제가 있는 환자들을 자주 대면하는 파주시지역사회 보장협의체 건강분과 위원을 대상으로 진행되었습니다.</span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 지역의료 발전에 공헌하고자 다채로운 의료봉사 프로그램을 진행할 예정입니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""></p><p><br></p><p><img src="/uploads/editor/515354bfe2d630dae015c80e12f1bbe7.jpg" data-filename="심폐소생술1.jpg" style="width: 500px;"></p><p><br></p><p><img src="/uploads/editor/e2fac56a757c89c587cf28b9fe2958e6.jpg" data-filename="심폐소생술2.jpg" style="width: 500px;"><br></p>', 3294, '112.161.27.82', 0, 0, 0, NULL, '2023-07-11 10:44:46', '2023-07-11 12:53:11', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1),
	(124, NULL, 1, '2023년 경기도 북서권역 응급의료 지역화 체계 구축 협의회 계획', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 7월 7일 \'2023년 경기도 북서권역 응급의료 지역화 체계 구축 협의회 계획\'에 대한 간담회가 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">이번 간담회는 경기도 북서권역 내 응급의료 현황 및 문제점을 파악하여 권역에 적합한 응급 의료 체계 지역화 구축 및 개선 방안을 논하는 시간이었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 지역의료 발전에 공헌하고자 다채로운 의료봉사 프로그램을 진행할 예정입니다.</span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><img src="/uploads/editor/9facf8e81fdb208120f5909114b6ee42.jpg" data-filename="응급실 교육1.jpg" style="width: 500px;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span><br></p>', 3278, '112.161.27.82', 0, 0, 0, NULL, '2023-07-12 15:09:05', '2023-07-12 15:09:05', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
