	(147, NULL, 1, '2023년 사회복지의 날 기념행사, 심폐소생술 교육 및 체험 행사', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 9월 6일 ‘2023년 사회복지의 날 기념행사’가 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 심폐소생술 교육 및 체험 행사를 진행하였습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 지역사회 의료발전에 공헌하고자 다양한 프로그램을 진행하고 있습니다.</span><br></p><p><br></p><p><img src="/uploads/editor/c5a3bf25b06d0400a0334591fdd6edb3.jpg" data-filename="사회복지의날1.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/c6ca72fa969f5732bfe944b3662bdc40.jpg" data-filename="사회복지의날2.jpg" style="width: 50%;"></p><p><br></p><p><img src="/uploads/editor/3bcecfa080d6ad652e0649726aea48fc.jpg" data-filename="사회복지의날3.jpg" style="width: 50%;"></p><p><br></p><p><br></p><p><img src="/uploads/editor/3fba991e6d9633d8a429d9522fc52edb.jpg" data-filename="사회복지의날4.jpg" style="width: 50%;"><br></p>', 1843, '112.161.27.82', 0, 0, 0, NULL, '2023-09-07 13:42:16', '2023-09-07 13:42:16', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
