	(150, NULL, 1, '찾아가는 무료 치매 검사 !', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 9월 한달간 매주 금요일&nbsp;</span><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">찾아가는 무료 치매 검사를 진행합니다.</span><br></p><p><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">만 60세 이상 어르신 1년에 1번 꼭! 치매검사 받으세요~</span><br></p><p><br></p><p><br></p><p><img src="/uploads/editor/59cb3c207b7e50b7cde421ea02dfedd3.jpg" data-filename="치매검사.jpg" style="width: 800px;"><br></p>', 2836, '112.161.27.82', 0, 0, 0, NULL, '2023-09-12 17:40:53', '2023-09-12 17:40:53', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
