	(151, NULL, 1, '국내·외 빈곤아동지원 캠페인 \'폼폼진행', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 국내·외 빈곤아동지원 캠페인 \'폼폼\' 행사를 9월 11일~15일까지 진행합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">국제구호개발 NGO단체의 정신을 홍보하고 빈곤아동을 돕기 위한 이번 캠페인에 많은 부탁드립니다.</span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><img src="/uploads/editor/d59007dc81f663572be3c4a80cdc59bd.jpg" data-filename="KakaoTalk_20230911_153706629.jpg" style="width: 800px;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p>', 2925, '106.240.238.122', 0, 0, 0, NULL, '2023-09-12 17:55:09', '2023-09-21 17:41:07', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000081', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
