	(158, NULL, 1, '환자안전&감염관리 주간행사', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 9월19일~20일 이틀간 \'환자안전&amp;감염관리 주간행사\'가 진행되었습니다.</span><br></p><p><br></p><p><img src="/uploads/editor/f597524834e7d7922f77e391d7875534.jpg" data-filename="환자안전1.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 600px;"><br></p><p><br></p><p><img src="/uploads/editor/d0fe164571b1dfe196e0ec51490acf39.jpg" data-filename="환자안전2.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 600px;"><br></p><p><br></p><p><img src="/uploads/editor/19a7c494b32ef83a81c3febb135eeaa3.jpg" data-filename="환자안전3.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/8d179b3751472c5dfe8ae7d70668d21e.jpg" data-filename="환자안전4.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/7f1085c2dcf169500cc3de245adcfea1.jpg" data-filename="환자안전5.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/e0a1a5a8a2101ab64be150a0785144dc.jpg" data-filename="환자안전6.jpg" style="font-family: inherit; letter-spacing: -0.02em; width: 600px;"><br></p><p><br></p><p><img src="/uploads/editor/2ccc2d515fedc28e83c0c2e8d2a5a1e5.jpg" data-filename="환자안전7.jpg" style="width: 600px;"><br></p>', 1903, '112.161.27.82', 0, 0, 0, NULL, '2023-09-25 17:35:40', '2023-09-25 17:35:40', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000085', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
