	(160, NULL, 1, '9월26일 재난 모의 훈련\'을 진행', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 9월 26일 메디인병원은 대규모 인명 사고 발생을 대비한 \'재난 모의 훈련\'을 진행하였습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">이번 훈련은 대표원장 중심의 지휘본부를 구축하고 응급실과 관련 부처간의 상황을 보다 빠르게 공유하여 대규모 재난 상황을 보다 신속하고 정확하게 대처하는 것에 중점을 두었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">메디인병원은 주기적인 교육을 통해 모든 직원이 유기적인 재난 상황에서도 정확하고 신속하게 대처할 수 있도록 노력하겠습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">파주 최초 민간 종합병원 메디인 병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><br></p><p><img src="/uploads/editor/492f3d5696c02f4af4cec406c0fadb02.jpg" data-filename="재난모의훈련1.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/a27437502a400fbbf26529376498d38c.jpg" data-filename="재난모의훈련2.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/f3450267164ed5c9f0b539b0c1850c7c.jpg" data-filename="재난모의훈련3.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/97cec4512501712c12701e6d308d9aed.jpg" data-filename="재난모의훈련4.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/5b6293daef42fe17d3dd4833f06b1af8.jpg" data-filename="재난모의훈련5.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/9fb490f6cdcd7b375c515c579323fdbc.jpg" data-filename="재난모의훈련6.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/e502cc4c846c8702e29b0f0b4fac84c6.jpg" data-filename="재난모의훈련7.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/ea24da75710f8a555a6dd2b7e351542f.jpg" data-filename="재난모의훈련8.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/e9d33c073696c81466e082ea4a3a006b.jpg" data-filename="재난모의훈련9.jpg" style="width: 600px;"></p><p><br></p><p><img src="/uploads/editor/79c6a27bce146971d115ee7280aa5168.jpg" data-filename="재난모의훈련10.jpg" style="width: 600px;"><br></p>', 1395, '112.161.27.82', 0, 0, 0, NULL, '2023-10-05 15:31:14', '2023-10-05 15:31:14', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000088', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
