	(179, NULL, 1, '메디인병원 신규간호사 공개 채용', '관리자', NULL, '<p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 9일 ‘메디인병원 신규간호사 공개 채용’이 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">멀리까지 와주신 모든 지원자분들 감사 드립니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">파주 최초 민간 종합병원 메디인병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><br></p><p><br></p><p><img src="/uploads/editor/cf48c6843f9bf9dbb2684bed0b30700e.jpg" data-filename="01.jpg" style="width: 500.333px; height: 500.333px;"></p><p><br></p><p><img src="/uploads/editor/258a41799f769219f0cdba1e37d90500.jpg" data-filename="02.jpg" style="width: 500px;"></p><p><br></p><p><img src="/uploads/editor/0dba604948f7af386ca188485451b139.jpg" data-filename="03.jpg" style="width: 500px;"></p><p><br></p><p><img src="/uploads/editor/ab40d24bebf31d576d54bacece2c4eef.jpg" data-filename="04.jpg" style="width: 500px;"><br></p><p><br></p><p><br></p>', 3071, '112.161.27.82', 0, 0, 0, NULL, '2023-11-10 17:52:41', '2023-11-10 17:52:41', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000107', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
