	(183, NULL, 1, '운정종합사회복지관에서 의료자원봉사', '관리자', NULL, '<p><br></p><p class="MsoNormal"><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">메디인병원은</span><span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"> </span><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">지난</span><span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"> <span lang="EN-US">15</span></span><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">일</span><span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"> </span><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">운정종합사회복지관에서</span><span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"> </span><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">의료자원봉사를</span><span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"> </span><span style="font-size: 9pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">진행했습니다</span><span lang="EN-US" style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">. <o:p></o:p></span></p><p>\r\n\r\n<span lang="EN-US" style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;;"><br>\r\n</span></p><p><span lang="EN-US" style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;;"><br></span><span style="font-size: 9pt; font-family: &quot;맑은 고딕&quot;; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">메디인병원은<span style="font-size: 9pt; font-family: &quot;Segoe UI&quot;, &quot;sans-serif&quot;; background-image: initial; background-position: initial; 