INSERT IGNORE INTO `board_tbl` (`BD_IDX`, `P_BD_IDX`, `BMT_IDX`, `BD_TITLE`, `BD_WRITER`, `BD_PWD`, `BD_CONTENT`, `BD_VIEW`, `BD_IP`, `BD_ORD`, `BD_REP_DEPTH`, `BD_STEP`, `BD_OPEN_FLAG`, `INPUTDATE`, `UPDATEDATE`, `BCST_IDX_1`, `BD_OPEN_LEVEL`, `BD_DEL_FLAG`, `DELDATE`, `BD_NOTICE_YN`, `IN_MEM_ID`, `UP_MEM_ID`, `DEL_MEM_ID`, `TAG`, `ATCH_FILE_ID`, `GN_CD`, `BD_OPEN_YN`, `BD_FIELD_1`, `BD_FIELD_2`, `BD_FIELD_3`, `BD_FIELD_4`, `BD_FIELD_5`, `BD_FIELD_6`, `BD_FIELD_7`, `BD_FIELD_8`, `BD_FIELD_9`, `BD_FIELD_10`, `T_ATCH_FILE_ID`, `A_ATCH_FILE_ID`, `BCST_IDX_2`, `BCST_IDX_3`, `BD_TEXT_1`, `BD_TEXT_2`, `BD_TEXT_3`, `W_ATCH_FILE_ID`, `BD_FIELD_11`, `BD_FIELD_12`, `BD_FIELD_13`, `BD_FIELD_14`, `BD_ORD_NEW`) VALUES
	(187, NULL, 1, ' ‘4주기 의료기관 인증’ 획득을 위한 의료기관 평가 인증 조사', '관리자', NULL, '<p><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">메디인병원은 지역민들에게 더욱 수준 높은 의료 서비스 제공을 위해 ‘4주기 의료기관 인증’ 획득을 위한 의료기관 평가 인증 조사를 12월 5일부터 8일까지 4일간 진행하였습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">보건복지부에서 주관하는 의료기관 평가 인증은 환자안전과 의료 서비스 질 향상에 목적을 두고 의료기관의 서비스와 운영 실태 등을 평가하는 제도입니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">‘4주기 의료기관 인증’ 획득을 위해 노력해 주신 모든 직원분들 고생 많으셨습니다. </span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">그동안 노력한 만큼 좋은 결과를 기대해 봅니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">메디인병원은 시설 및 환경에 대한 지속적인 노력과 시설투자를 병행하여 앞으로도 환자 안전과 의료의 질 향상을 위해 끊임없이 노력하겠습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">힘써주신 모든분들께 다시 한번 감사의 인사를 전합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;">파주 최초 민간 종합병원 메디인병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공합니다.</span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 16px; letter-spacing: normal;"><br></span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"></p><p><img src="/uploads/editor/92037cc938f5faed8f0fc8dbb628f2bc.jpg" data-filename="인증1.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/08527ce849eb23ddf9a4557dd1260a2f.jpg" data-filename="인증2.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/b30e8a7ed86ecc1ef8b3d63232b8a641.jpg" data-filename="인증3.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/e6871ab42f3f93d926fb6b589dbabdee.jpg" data-filename="인증4.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/973404cc69fd7d0049ddc42efbfdf85e.jpg" data-filename="인증5.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/f65d477fdbfa25ddac7bb510fb776c3f.jpg" data-filename="인증6.jpg" style="width: 800px;"></p><p><img src="/uploads/editor/108a6bd34c9e3540b198263fba8e848a.jpg" data-filename="인증7.jpg" style="width: 800px;"><br></p>', 2918, '112.161.27.82', 0, 0, 0, NULL, '2023-12-08 17:07:35', '2024-01-25 11:09:46', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000115', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
