	(200, NULL, 1, '제2회 QI 경진대회가 진행되었습니다.', '관리자', NULL, '<p><br></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></span></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">지난 1월24일(수) 메디인병원 제2회 QI 경진대회가 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">환자의 안정과 의료질 향상을 위해 지난 1년간 노력해주신 모든분들 고생많으셨습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><span style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;">파주 최초 민간 종합병원 메디인병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br style="font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; font-size: 14px; letter-spacing: normal;"><br></p><p><br></p><p><img src="/uploads/editor/78d9be2ab09d8cc844f69cfad797a64a.jpg" data-filename="경진대회1.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/c90467add48bdeaf14751589b9742f9d.jpg" data-filename="경진대회2.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/cce04b39aee04c1d5d0e7cb7f05ae250.jpg" data-filename="경진대회3.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/5c7133713ef80b77768703993bb5aff2.jpg" data-filename="경진대회4.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/b75a7cd1d4a3af489150658eb5bb6767.jpg" data-filename="경진대회5.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/77b26fb600699df4e3479fbcd20d2b59.jpg" data-filename="경진대회6.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/3a63734ad2dd5be375f6b5d6ae813c14.jpg" data-filename="경진대회7.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/501af5915e20a7906a58509af33f3341.jpg" data-filename="경진대회8.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/22489da3e8e92b400a2bf8d6ee5b9b17.jpg" data-filename="경진대회9.jpg" style="width: 800px;"></p><p><br></p><p><br></p>', 3338, '112.161.27.82', 0, 0, 0, NULL, '2024-01-25 11:09:27', '2024-02-14 09:26:53', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000135', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
