	(276, NULL, 1, '신의열 화백님께서 작품 \'고와리의 풍경\' 을 기증해 주셨습니다.', '관리자', NULL, '<p><br></p><p><br></p><p>지난 9월 24일 신의열 화백님께서 작품 \'고와리의 풍경\' 을 기증해 주셨습니다.</p><p>화백님의 소중한 기증에 진심으로 감사드리며, 신의열 화백님의 건강을 기원합니다.</p><p><br></p><p><br></p><p><img src="/uploads/editor/2c893c0da3077030313241e31e348d81.jpg" data-filename="0924 신의열화백1.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/ba6910fe7b36aa4eeb6fb3b661ca4b58.jpg" data-filename="0924 신의열화백3.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/75ba2c52b401a423e080428a62b1c7cd.jpg" data-filename="0924 신의열화백2.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/5fdd2245dbb219b6314e833c181d8ec8.jpg" data-filename="허혈성 심장질환9.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/a6bb58bd23e8cdbcee06dafbf0ea62a8.jpg" data-filename="허혈성 심장질환10.jpg" style="width: 800px;"></p><p><br></p><p><br></p>', 1351, '112.161.27.82', 0, 0, 0, NULL, '2024-09-30 17:12:05', '2024-10-25 17:40:37', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000293', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
