	(281, NULL, 1, '심평원 간담회 ', '관리자', NULL, '<p><br></p><p><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">지난 10월 7일 경기북부 종합병원 대상으로 현장중심 소통 강화를 통해 건강한 의료문화 환경을 조성하고자 메디인 병원과 심평원의 간담회가 진행되었습니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">파주 최초 민간 종합병원 메디인병원은 대학병원급 첨단 장비를 이용한 수준 높은 의료 서비스를 제공합니다.</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">▶운정/파주종합병원, 메디인병원</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">▶파주시 금릉역로 190</span><br style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"=""><span style="font-family: -apple-system, BlinkMacSystemFont, " segoe="" ui",="" roboto,="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" letter-spacing:="" normal;"="">▶문의) 1566-1991</span><br></p><p><br></p><p><img src="/uploads/editor/b262f6d98825a5c7c4f96117c2951a14.jpg" data-filename="심평원간담회1.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/5d7b3774c9b9f845ae15b00e0e436c94.jpg" data-filename="심평원간담회2.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/59c9b7ca797d46387362f1428f25088c.jpg" data-filename="심평원간담회3.jpg" style="width: 800px;"></p><p><br></p><p></p><p><br></p><p><img src="/uploads/editor/ebb5b9882ff4ddca98d1db40e4edff23.jpg" data-filename="심평원간담회5.jpg" style="width: 800px;"></p><p><br></p><p><img src="/uploads/editor/565b7dd3964e937771536483ec4f8b9c.jpg" data-filename="심평원간담회6.jpg" style="width: 800px;"></p><p><br></p><p><br></p>', 1739, '112.161.27.82', 0, 0, 0, NULL, '2024-10-10 14:09:12', '2026-04-03 15:04:36', NULL, NULL, 'N', NULL, 'N', 'admin', 'admin', NULL, NULL, NULL, 'GN06000000', 'Y', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '', 'FID00000299', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1);
